window.allTests["test_u1_askeri_1"] = [
    {
        soru: " <i>\"Dandanakan’da Selçuklular, Gaznelileri ağır bir yenilgiye uğrattı. Bu zafer yalnızca askeri bir üstünlük değil, Türk liderliğinin Orta Asya bozkırından Orta Doğu’ya taşınmasının simgesiydi. Artık Horasan, yeni bir güç merkezinin kalbi olacaktı.\" — Osman Turan, Selçuklular Tarihi ve Türk-İslam Medeniyeti, Ötüken Yayınları, 2014</i><br><br><b>Metne göre Dandanakan Savaşı’nın (1040) Türk tarihi açısından taşıdığı temel anlam nedir?</b>",
        secenekler: [
            "A) Gaznelilerin İslam coğrafyasından tamamen silinmesi",
            "B) Türk siyasi ağırlığının Orta Asya’dan Orta Doğu’ya kayması",
            "C) Abbasi halifeliğinin Selçuklu himayesine girmesi",
            "D) İpek Yolu’nun Türk kontrolüne geçmesi",
            "E) Türk boylarının Anadolu’ya ilk kez geçmesi"
        ],
        cevap: "B) Türk siyasi ağırlığının Orta Asya’dan Orta Doğu’ya kayması",
        aciklama: "Turan’ın metni, Dandanakan’ı salt askeri bir olay olarak değil Türk siyasi liderliğinin Orta Asya’dan İslam dünyasının merkezine taşınmasının simgesi olarak ele alır. \"Horasan’ın yeni bir güç merkezine dönüşmesi\" ifadesi coğrafi ve siyasi bir ağırlık kaymasını açıkça ortaya koyar."
    },
    {
        soru: " <i>\"Malazgirt, Bizans ordusunun yenilgisinden çok daha fazlasıdır. Bu savaş, Türklere Anadolu’nun kapısını açmış; yüzyıllardır Hristiyan ve antik Roma mirasının taşıyıcısı olan bir yarımadayı kalıcı biçimde yeni bir medeniyetin yurduna dönüştürme sürecini başlatmıştır.\" — Claude Cahen, Osmanlılardan Önce Anadolu, çev. Erol Üyepazarcı, Tarih Vakfı Yurt Yayınları, 2000</i><br><br><b>Metne göre Malazgirt Savaşı’nın (1071) önemi nasıl tanımlanmaktadır?</b>",
        secenekler: [
            "A) Bizans İmparatorluğu’nun siyasi olarak sona ermesi",
            "B) Anadolu’nun yalnızca kısa süreli Türk işgaline uğraması",
            "C) Anadolu’nun kalıcı olarak yeni bir medeniyetin yurduna dönüşme sürecinin başlaması",
            "D) Türklerin İstanbul’u fethedecek gücü elde etmesi",
            "E) Haçlı Seferlerinin doğrudan tetikleyicisi olması"
        ],
        cevap: "C) Anadolu’nun kalıcı olarak yeni bir medeniyetin yurduna dönüşme sürecinin başlaması",
        aciklama: "Cahen, Malazgirt’i Bizans’ın askeri yenilgisi olarak değil; \"yüzyıllardır Hristiyan ve antik Roma mirasının taşıyıcısı olan bir yarımadanın yeni bir medeniyetin yurduna dönüşme sürecinin başlangıcı\" olarak tanımlar. Savaşın uzun vadeli medeniyetsel dönüşümü merkeze alır."
    },
    {
        soru: " <i>\"Haçlı Seferleri, Türk-Müslüman devletlerini hem savunmaya zorlamış hem de yeni ittifak arayışlarına itmiştir. Öte yandan bu seferler, İslam dünyasının toparlanma sürecinde Türk askeri gücünün belirleyici rolünü pekiştirmiştir.\" — Steven Runciman, Haçlı Seferleri Tarihi, çev. Fikret Işıltan, Türk Tarih Kurumu, 1992</i><br><br><b>Metne göre Haçlı Seferleri’nin Türk devletleri üzerindeki en belirgin etkisi nedir?</b>",
        secenekler: [
            "A) Türk devletlerinin kalıcı olarak çökmesi",
            "B) Türk askeri gücünün İslam dünyasındaki rolünü pekiştirmesi",
            "C) Türklerin Hristiyanlığı benimsemeleri",
            "D) Orta Asya Türk boylarının batıya göçünü durdurması",
            "E) Selçuklu-Bizans ittifakının kurulması"
        ],
        cevap: "B) Türk askeri gücünün İslam dünyasındaki rolünü pekiştirmesi",
        aciklama: "Runciman, Haçlı Seferleri’nin Türk-Müslüman devletlerini savunmaya zorladığını ama aynı zamanda bu devletlerin toparlanma sürecinde Türk askeri gücünün belirleyici bir rol üstlendiğini vurgular. Haçlı tehdidi, paradoks biçimde Türk askeri liderliğini daha görünür kılmıştır."
    },
    {
        soru: " <i>\"Kösedağ’da Moğollar karşısında uğranılan yenilgi, Anadolu Selçuklu Devleti’nin siyasi bağımsızlığını fiilen sona erdirdi. Sultanlar tahtlarında otururken gerçek otorite Moğol komutanların elinde kalmaya başladı.\" — Ahmet Yaşar Ocak, Türkler, Türkiye ve İslam, İletişim Yayınları, 2012</i><br><br><b>Metne göre Kösedağ Savaşı’nın (1243) Selçuklu Devleti’ne temel etkisi nedir?</b>",
        secenekler: [
            "A) Selçuklu topraklarının Moğollara tamamen devredilmesi",
            "B) Selçukluların Moğollarla kalıcı bir ittifak kurması",
            "C) Selçuklu sultanlarının fiili iktidarını yitirerek Moğol denetimine girmesi",
            "D) Selçukluların Mısır’a sığınarak yeni bir devlet kurması",
            "E) Moğolların Anadolu’ya yerleşerek Türk kültürünü benimsemesi"
        ],
        cevap: "C) Selçuklu sultanlarının fiili iktidarını yitirerek Moğol denetimine girmesi",
        aciklama: "Ocak’ın metni, Kösedağ’ın ardından Selçuklu sultanlığının sembolik olarak sürdüğünü; ancak gerçek iktidarın Moğol komutanlarına geçtiğini belirtir. Bu tablo nominal egemenlik ile fiili otorite arasındaki derin kopuşu simgeler."
    },
    {
        soru: " <i>\"Myriokephalon’dan sonra İmparator Manuel, bir daha Türklere karşı büyük bir sefer düzenleme cesaretini kendinde bulamadı. Bizans, artık Anadolu’nun iç kesimlerini Türklerden geri alma umudundan vazgeçmek zorunda kaldı.\" — Niketas Khoniates, Historia, çev. Bilge Umar, Dünya Yayınları, 2010</i><br><br><b>Metne göre Myriokephalon Savaşı’nın (1176) Bizans’a etkisi nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Bizans’ın Anadolu’daki askeri gücünü tamamen yeniden kazanması",
            "B) Bizans’ın Anadolu’nun iç kesimlerini geri alma umudunu yitirmesi",
            "C) İki taraf arasında kalıcı bir barış antlaşmasının imzalanması",
            "D) Bizans ordusunun tamamen yok edilmesi",
            "E) Selçukluların İznik’i geri fethetmesi"
        ],
        cevap: "B) Bizans’ın Anadolu’nun iç kesimlerini geri alma umudunu yitirmesi",
        aciklama: "Niketas Khoniates, Myriokephalon’dan sonra imparator Manuel’in bir daha büyük sefer yapamadığını ve Bizans’ın iç Anadolu’yu geri alma umudunu yitirdiğini belgeler. A şıkkı tarihsel gerçeğin tam tersidir."
    },
    {
        soru: " <i>\"1048’de Pasinler’de Türk kuvvetleri, Bizans ve Gürcü kuvvetlerini bozguna uğrattı. Bu savaş; Malazgirt’ten önce Bizans’ın Türk akınlarını durduramayacağını gösteren kritik bir test oldu. Bizans’ın sınır savunma sisteminin artık işlemediği görüldü.\" — Speros Vryonis, The Decline of Medieval Hellenism in Asia Minor, University of California Press, 1971</i><br><br><b>Pasinler Savaşı’nı (1048) Malazgirt Savaşı’nın (1071) bir \"öncülü\" olarak yorumlamamızın tarihsel dayanağı nedir?</b>",
        secenekler: [
            "A) Bizans İmparatoru’nun Pasinler’de esir alınması",
            "B) Bizans’ın Türk akınlarını durduramayacağını erkenden ortaya koyması",
            "C) Selçukluların bu savaşta Anadolu’nun tamamını fethetmesi",
            "D) Türklerin Pasinler’de ilk kez düzenli ordu kurması",
            "E) Gürcülerin bu savaştan sonra Selçuklu himayesine girmesi"
        ],
        cevap: "B) Bizans’ın Türk akınlarını durduramayacağını erkenden ortaya koyması",
        aciklama: "Vryonis, Pasinler’in Malazgirt’ten yaklaşık 23 yıl önce Bizans’ın Türk akınlarını askeri olarak durduramayacağını gösterdiğini belirtir. Pasinler, Malazgirt’in rastlantısal değil; yapısal bir zafer olduğunu önceden işaret eden kritik bir savaştır."
    },
    {
        soru: " <i>\"Dandanakan’dan sonra Selçuklular iki yönde genişledi: Batıda Abbasi halifeliğini koruma altına alarak meşruiyet sağladılar, doğuda ise Horasan ve Maveraünnehir’i güvence altına aldılar. Böylece bir bozkır devleti olmaktan çıkıp İslam dünyasının hamisi rolüne büründüler.\" — İbrahim Kafesoğlu, Selçuklu Tarihi, Millî Eğitim Bakanlığı Yayınları, 1992</i><br><br><b>Metne göre Dandanakan Savaşı, Selçukluların devlet karakterini nasıl dönüştürmüştür?</b>",
        secenekler: [
            "A) Selçukluları yalnızca askeri bir güç olarak konumlandırmıştır",
            "B) Selçukluları bir bozkır topluluğundan İslam dünyasının hamisi rolüne taşımıştır",
            "C) Selçukluların Hristiyanlığı kabul etmesine zemin hazırlamıştır",
            "D) Selçukluların yalnızca Orta Asya’da kalmalarını sağlamıştır",
            "E) Selçukluların Abbasi halifeliğini ortadan kaldırmasına yol açmıştır"
        ],
        cevap: "B) Selçukluları bir bozkır topluluğundan İslam dünyasının hamisi rolüne taşımıştır",
        aciklama: "Kafesoğlu’nun metni, Dandanakan’ın Selçuklular için salt askeri değil kimliksel ve kurumsal bir dönüşüm kapısı olduğunu vurgular. Selçuklular bu zaferle \"bozkır devleti\" kimliğinden çıkıp Abbasi halifesinin hamisi sıfatıyla İslam dünyasının merkezine taşındı."
    },
    {
        soru: " <i>\"Malazgirt’ten sonra Bizans, Türkleri durdurmak için daha önce ödemeye gerek duymadığı bir bedeli ödedi: İç siyasi çalkantılar, askeri harcamalar ve toprak kayıpları. İmparatorluk, bu yenilginin yarattığı krizi bir türlü aşamadı; Türkler ise toprak kazanımlarını sistematik biçimde pekiştirdi.\" — John Haldon, Byzantium at War, Osprey Publishing, 2002</i><br><br><b>Malazgirt Savaşı’nın Bizans üzerindeki siyasi ve kurumsal etkisini değerlendiren bu metne göre hangi yorum doğrudur?</b>",
        secenekler: [
            "A) Bizans, Malazgirt’ten sonra güçlenerek Türkleri Anadolu’dan püskürttü",
            "B) Yenilgi Bizans’ta iç krizleri derinleştirirken Türkler kazanımlarını kalıcılaştırdı",
            "C) Malazgirt’in siyasi sonuçları yalnızca kısa vadede etkili oldu",
            "D) Bizans bu yenilgiden sonra doğu sınırından çekilmeyi tercih etti",
            "E) İki taraf yenilginin ardından derhal antlaşma imzaladı"
        ],
        cevap: "B) Yenilgi Bizans’ta iç krizleri derinleştirirken Türkler kazanımlarını kalıcılaştırdı",
        aciklama: "Haldon’ın analizi, Malazgirt’in Bizans’ta iç siyasi çalkantıları derinleştirirken Türklerin kazanımlarını sistematik biçimde pekiştirdiğini ortaya koyar. Bir yenilginin iki taraf üzerindeki asimetrik etkisine dikkat çeken önemli bir yorumdur."
    },
    {
        soru: " <i>\"I. Haçlı Seferi, Türkiye Selçuklularını ağır biçimde sarstı; İznik başkentleri Bizans ve Haçlılar tarafından geri alındı. Ancak Selçuklular merkezlerini Konya’ya taşıyarak hayatta kalmayı başardılar. Bu kriz, onları daha esnek ve dayanıklı bir iç örgütlenmeye yöneltti.\" — Rustam Shukurov, The Byzantine Turks 1204–1461, Brill, 2016</i><br><br><b>I. Haçlı Seferi’nin Türkiye Selçukluları üzerindeki etkisini ele alan bu metne göre söz konusu krizin paradoksal sonucu nedir?</b>",
        secenekler: [
            "A) Selçukluların tamamen çökerek Haçlı egemenliğini kabul etmesi",
            "B) Selçukluların krizi atlayarak daha esnek bir yapıya kavuşması",
            "C) Haçlı Seferi’nin Selçuklu-Bizans ittifakını güçlendirmesi",
            "D) İznik’in kalıcı olarak Türk egemenliğinde kalması",
            "E) Selçukluların Suriye’ye çekilerek burada yeni bir devlet kurması"
        ],
        cevap: "B) Selçukluların krizi atlayarak daha esnek bir yapıya kavuşması",
        aciklama: "Shukurov’un tezi krizin paradoksal boyutuna dikkat çeker: İznik’in kaybı ve merkezin Konya’ya taşınması, Selçukluların hayatta kalma ve esneme kapasitesini göstermiştir. \"Kriz = çöküş\" şeklindeki mekanik düşünce kalıbının ötesine geçmeyi gerektiren bir sorudur."
    },
    {
        soru: " <i>\"Sultan Alp Arslan’ın Malazgirt’te elde ettiği zaferden kısa süre sonra Türk boylarının Anadolu içlerine dalgalar hâlinde aktığı görüldü. Bu süreç kontrollü bir fetihten çok kendiliğinden gelişen bir iskân hareketiydi. Bozkır alışkanlıklarıyla gelen Türkmen grupları, çoban ekonomileriyle yeni topraklara uyum sağladı.\" — Faruk Sümer, Oğuzlar (Türkmenler): Tarihleri, Boy Teşkilatı, Destanları, Türk Dünyası Araştırmaları Vakfı, 1999</i><br><br><b>Metne göre Malazgirt sonrası Anadolu’nun Türkleşmesini merkezi bir fetih politikasından ayırt eden en belirgin özellik nedir?</b>",
        secenekler: [
            "A) Türkmenlerin Bizans halkını zorla göç ettirmesi",
            "B) Türk boylarının serbest ve kendiliğinden bir iskân hareketiyle Anadolu’ya yayılması",
            "C) Selçuklu sultanlarının her boyun yerleşeceği bölgeyi bizzat belirlemesi",
            "D) Türk göçünün yalnızca Doğu Anadolu ile sınırlı kalması",
            "E) Türkmenlerin Anadolu’ya geçmeden önce İslam’ı benimsemiş olması"
        ],
        cevap: "B) Türk boylarının serbest ve kendiliğinden bir iskân hareketiyle Anadolu’ya yayılması",
        aciklama: "Faruk Sümer, Anadolu’nun Türkleşmesini merkezi devlet politikasından ziyade kendiliğinden gelişen bir iskân hareketi olarak tanımlar. Türk fethini yalnızca siyasi-askeri değil sosyolojik boyutuyla da anlamayı gerektirir."
    },
    {
        soru: " <i>\"Myriokephalon’dan sonra imzalanan antlaşma şartları, Bizans’ın Türk varlığını Anadolu’nun kalıcı bir unsuru olarak fiilen tanıması anlamına geliyordu. Bu, bir savaş meydanı zaferinden öte bir jeopolitik kabuldü.\" — Paul Magdalino, The Empire of Manuel I Komnenos, Cambridge University Press, 1993</i><br><br><b>Metne göre Myriokephalon Savaşı’nın (1176) siyasi önemi neden yalnızca askeri bir zaferle açıklanamaz?</b>",
        secenekler: [
            "A) Selçukluların bu savaştan sonra Bizans’a haraç ödemesi",
            "B) Savaşın Bizans’ın Türk varlığını kalıcı olarak tanımasıyla sonuçlanması",
            "C) İki tarafın bu savaştan sonra ortak bir ordu oluşturması",
            "D) Bizans’ın Myriokephalon’dan sonra toprak kazanmaya devam etmesi",
            "E) Selçukluların bu zafer sayesinde Abbasi hilafetinin desteğini kazanması"
        ],
        cevap: "B) Savaşın Bizans’ın Türk varlığını kalıcı olarak tanımasıyla sonuçlanması",
        aciklama: "Magdalino, Myriokephalon sonrası antlaşmanın yalnızca askeri bir teslimiyet değil Bizans’ın Türk varlığını jeopolitik bir gerçek olarak kabul etmesi anlamına geldiğini vurgular. Bir savaşın barış antlaşmasındaki siyasi içeriğini analiz etmeyi gerektirir."
    },
    {
        soru: " <i>\"Kösedağ’dan sonra Anadolu Selçuklu Devleti, Moğol İlhanlı tabiiyeti altında yarı özerk bir varlık sürdürdü. Sultanlar tahta Moğol onayıyla otururken devlet gelirleri büyük ölçüde İlhanlı hazinesine aktarıldı. Bu tablo, egemenlikten çok idari bir vasallığa işaret ediyordu.\" — Abdülkadir Yuvalı, İlhanlılar Tarihi, Erciyes Üniversitesi Yayınları, 1994</i><br><br><b>Metne göre Kösedağ sonrası Selçuklu yönetimini “egemenlik” yerine “vasallık” kavramıyla tanımlamak ne açıdan yerindedir?</b>",
        secenekler: [
            "A) Selçuklu hanedanının tamamen ortadan kalkması",
            "B) Sultanların tahta oturması ama gerçek iktidarı Moğollara bırakması",
            "C) Selçuklu ordusunun Moğol kuvvetleriyle birleşmesi",
            "D) Anadolu’da Moğol kültürünün Türk kültürünü tamamen dönüştürmesi",
            "E) Selçuklu topraklarının Moğol boyları arasında paylaşılması"
        ],
        cevap: "B) Sultanların tahta oturması ama gerçek iktidarı Moğollara bırakması",
        aciklama: "Yuvalı’nın metni, Selçuklu sultanlarının tahtta oturmaya devam etmesini egemenlikle değil vasallık ilişkisiyle açıklar. Moğol onayı olmadan tahta çıkılamaması ve gelirlerin İlhanlılara aktarılması bu vasallığın somut göstergeleridir."
    },
    {
        soru: " <i>\"Harzemşah Celaleddin’in Anadolu’ya girişi, Selçuklular için hem bir tehdit hem de bir fırsattı. Tehdit; Türk coğrafyasının iç savaşa sahne olmasıydı. Fırsat ise Moğol tehdidine karşı ortak bir cephe oluşturma imkânıydı. Ne var ki Yassıçimen’de bu fırsat heba edildi.\" — Nesimi Yazıcı, İlk Türk-İslam Devletleri Tarihi, Türkiye Diyanet Vakfı Yayınları, 2002</i><br><br><b>Yassıçimen Savaşı’nı (1230) ele alan metne göre bu savaşın tarihsel açıdan en önemli fırsatı neden kaçırdığı söylenebilir?</b>",
        secenekler: [
            "A) Selçukluların bu savaşta ağır kayıplar vermesi",
            "B) Türk devletlerinin Moğol tehdidine karşı ortak cephe kurmak yerine birbirleriyle savaşması",
            "C) Harzemşahların İslam’ı terk etmesi",
            "D) Celaleddin’in savaştan kaçarak Hindistan’a sığınması",
            "E) Selçukluların Yassıçimen’de Moğollarla ittifak yapması"
        ],
        cevap: "B) Türk devletlerinin Moğol tehdidine karşı ortak cephe kurmak yerine birbirleriyle savaşması",
        aciklama: "Yassıçimen Savaşı, Moğol tehdidine karşı bir Türk-İslam dayanışması fırsatını fiilen heba etmiştir. İki Türk-Müslüman devletinin birbirleriyle çatışması Moğolların Anadolu’ya inmesini kolaylaştıran dolaylı bir etken olmuştur."
    },
    {
        soru: " <i>\"İbn Bibi, sultanın Kösedağ’a giderken ne kadar güvenli hissettiğini aktarır: Hazine doluydu, başkent şenliklere sahne oluyordu. Ama Moğol ordusuyla karşılaşıldığında bu güven çabucak çöktü. Kösedağ, sadece bir savaş değil, bir yanılsamanın da yenilgisiydi.\" — İbn Bibi, El-Evâmirü’l-Alâiyye fi’l-Umûri’l-Alâiyye, çev. Mürsel Öztürk, Kültür Bakanlığı Yayınları, 1996</i><br><br><b>İbn Bibi’nin aktarımına göre Kösedağ Savaşı, yalnızca askeri bir yenilgiyi değil aynı zamanda neyi simgelemiştir?</b>",
        secenekler: [
            "A) Selçuklu ekonomisinin çöküşünü",
            "B) Selçuklu sultanlarının kişisel cesaretsizliğini",
            "C) Güç ve refah yanılsamasının da yıkılmasını",
            "D) Halkın sultanlara olan güveninin sona ermesini",
            "E) Moğolların stratejik üstünlüğünü çok önceden fark etmelerini"
        ],
        cevap: "C) Güç ve refah yanılsamasının da yıkılmasını",
        aciklama: "İbn Bibi’nin anlatısında asıl vurgulanan husus, Selçuklu yönetim çevrelerinin güç ve refah yanılsaması içinde olmasıdır. Kösedağ hem askeri hem siyasi-psikolojik bir çöküşü temsil etmektedir. Birincil kaynak analizi gerektiren bu soru üst düzey okuma becerisini ölçer."
    },
    {
        soru: " <i>\"Türk edebiyatında Malazgirt, zafer kadar bir dönüm noktası olarak da işlenir. Orhan Pamuk’un eserlerinde İstanbul’un Türklüğü, doğrudan Malazgirt sonrasında başlayan göç ve iskân dalgasına dayandırılır. Tarihsel bellek, savaş alanlarında değil şehirlerin dokusunda yaşar.\" — Orhan Pamuk, İstanbul: Hatıralar ve Şehir, YKY, 2003 (Yorumsal atıf)</i><br><br><b>Metindeki yaklaşım değerlendirildiğinde Malazgirt’in Türk tarihsel belleğindeki anlamı nasıl yorumlanabilir?</b>",
        secenekler: [
            "A) Malazgirt yalnızca resmi tarihçilerin ilgilendiği teknik bir savaştır",
            "B) Savaşın anlamı şehirlerin ve toplumsal belleğin dokusunda yaşamaya devam etmektedir",
            "C) Türk edebiyatı Malazgirt’i olumsuz bir olay olarak değerlendirmektedir",
            "D) Malazgirt yalnızca Bizans tarih yazımında ele alınmaktadır",
            "E) Edebiyatta Malazgirt, ekonomik bir dönüşümün başlangıcı olarak işlenir"
        ],
        cevap: "B) Savaşın anlamı şehirlerin ve toplumsal belleğin dokusunda yaşamaya devam etmektedir",
        aciklama: "Malazgirt’in tarihsel önemini salt resmi tarih yazımının ötesinde edebiyat ve şehir belleği bağlamına yerleştiren bu metin, tarihsel hafızanın savaş alanlarıyla değil şehirlerin dokusu ve gündelik yaşamla devam ettiği fikrini öne çıkarır."
    }
];

window.allTests["test_u1_askeri_2"] = [
    {
        soru: " <i>\"I. Kılıç Arslan, 1101 Haçlı Seferleri sırasında birçok Haçlı ordusunu Anadolu’da bozguna uğrattı. Bu başarılar, Türkiye Selçuklularının yalnızca hayatta kalmadığını; aksine Anadolu’daki varlıklarını giderek güçlendirdiğini gösteriyordu.\" — Işın Demirkent, Haçlı Seferleri, Dünya Yayıncılık, 2007</i><br><br><b>I. Kılıç Arslan’ın 1101 Haçlı Seferlerine karşı verdiği başarılı mücadeleyi Türkiye Selçuklularının genel tarihsel konumu açısından nasıl yorumlamamız gerekir?</b>",
        secenekler: [
            "A) Bu başarılar Selçukluların Orta Doğu’daki liderliğini pekiştirdi",
            "B) Bu başarılar Selçukluların Anadolu’daki varlığını ve gücünü kalıcılaştırdı",
            "C) Bu başarılar sayesinde Selçuklular İstanbul’u kuşattı",
            "D) Bu başarılar Haçlı Seferlerinin tamamen durmasına yol açtı",
            "E) Bu başarılar Selçukluların Suriye ve Filistin’i ele geçirmesini sağladı"
        ],
        cevap: "B) Bu başarılar Selçukluların Anadolu’daki varlığını ve gücünü kalıcılaştırdı",
        aciklama: "I. Kılıç Arslan’ın 1101 seferlerindeki başarıları, Selçukluların yalnızca hayatta kalmadığını; bilakis askeri kapasitelerini geliştirip Anadolu’daki konumlarını pekiştirdiğini kanıtlar. Haçlı Seferleri’nin Türkleri her zaman geriletmediğini; aksine zaman zaman güçlendirdiğini gösterir."
    },
    {
        soru: " <i>\"Selçuklu iktâ sistemi, hem toprak yönetimini hem de orduyu finanse etmeyi olanaklı kıldı. Komutanlara belirli bölgelerin vergi gelirleri tahsis ediliyor; bu kişiler karşılığında askeri hizmet yükümlülüğü altına giriyordu. Böylece büyük bir orduyu merkezi hazine olmaksızın ayakta tutmak mümkün oldu.\" — Ann K. S. Lambton, Landlord and Peasant in Persia, Oxford University Press, 1953</i><br><br><b>İktâ sisteminin Selçuklu askeri başarılarına katkısını açıklayan metne göre bu sistemin temel işlevi nedir?</b>",
        secenekler: [
            "A) Topraksız köylülerin toprak sahibi yapılması",
            "B) Merkezi hazine kullanmadan büyük orduların sürdürülmesini mümkün kılması",
            "C) Ticaret gelirlerinin ordu için kullanılması",
            "D) Fethedilen toprakların doğrudan sultan ailesine dağıtılması",
            "E) Din adamlarının askeri lider olarak görevlendirilmesi"
        ],
        cevap: "B) Merkezi hazine kullanmadan büyük orduların sürdürülmesini mümkün kılması",
        aciklama: "Lambton’ın çalışması, iktâ sisteminin Selçuklu ordusunu merkezi hazine yükü olmaksızın finanse etmeyi mümkün kıldığını ortaya koyar. Kurumsal yapı ile askeri sonuç arasındaki ilişkiyi analiz etmeyi gerektiren bir sorudur."
    },
    {
        soru: " <i>\"Anna Komnene, Türk akıncılarının yalnızca savaşarak değil, yerleşerek, çobanlık yaparak, zanaatkâr olarak Anadolu’ya kök saldığını hayretle aktarır. Düşman olarak gelen bu insanlar, zamanla toprağın bir parçası hâline gelmişti.\" — Anna Komnene, Alexiad, çev. Bilge Umar, İnkılâp Kitabevi, 1996</i><br><br><b>Anna Komnene’nin gözlemlerine göre Türklerin Anadolu’ya yerleşme süreci nasıl gerçekleşmiştir?</b>",
        secenekler: [
            "A) Türkler Anadolu’ya yalnızca asker olarak gelip kısa sürede geri çekildi",
            "B) Türkler askeri fethin yanı sıra gündelik yaşamın bir parçası olarak da topraklara kök saldı",
            "C) Türkler Bizans halkını zorla sürerek onların topraklarını ele geçirdi",
            "D) Türklerin Anadolu’ya yerleşmesi yalnızca dini vakıflar aracılığıyla gerçekleşti",
            "E) Türkler Anadolu’ya yalnızca ticaret amacıyla geldi"
        ],
        cevap: "B) Türkler askeri fethin yanı sıra gündelik yaşamın bir parçası olarak da topraklara kök saldı",
        aciklama: "Anna Komnene’nin birincil tanıklığı, Türk iskânının askeri fetihten ibaret olmadığını; yerleşik hayat, çobanlık ve zanaat gibi gündelik yaşam pratikleriyle de gerçekleştiğini belgeler."
    },
    {
        soru: " <i>\"Moğol istilası, Anadolu’yu doğrudan yıkıma uğratmakla birlikte paradoksal bir sonuç da doğurdu: Orta Asya ve İran’dan kaçan bilginler, zanaatkârlar ve tasavvuf ehli Anadolu’ya sığındı. Böylece Anadolu, beklenmedik biçimde bir kültür merkezi hâline geldi.\" — Mikail Bayram, Ahi Evren ve Ahi Teşkilatının Kuruluşu, Damla Ofset, 1991</i><br><br><b>Metne göre Moğol istilasının Anadolu üzerindeki paradoksal kültürel etkisi nedir?</b>",
        secenekler: [
            "A) Moğolların Anadolu’da yeni camiler ve medreseler inşa etmesi",
            "B) İstiladan kaçan bilgin ve sanatçıların Anadolu’yu bir kültür merkezine dönüştürmesi",
            "C) Moğolların Türkçeyi Anadolu’da resmi dil ilan etmesi",
            "D) Selçuklu sanatçılarının Moğol kültürünü benimsemesi",
            "E) İstiladan kaçan halkın İran kültürünü Anadolu’ya taşımasının olumsuz etkileri"
        ],
        cevap: "B) İstiladan kaçan bilgin ve sanatçıların Anadolu’yu bir kültür merkezine dönüştürmesi",
        aciklama: "Moğol istilasının doğrudan yarattığı yıkımın yanında beklenmedik bir kültürel kazanım ürettiğini göstermektedir. \"Felaketten doğan kültür merkezi\" paradoksu, tarihsel süreçlerin karmaşıklığını anlamak için güçlü bir örnek sunar."
    },
    {
        soru: " <i>\"Kösedağ’ın ardından Anadolu Selçuklu merkezi otoritesi fiilen çökerken çevre bölgelerde küçük Türk beylikleri güç doldurmaya başladı. Bu beylikler, Selçuklu siyasi mirasını ve kültürel geleneğini taşırken aynı zamanda yeni bir siyasi rekabet ortamı yarattı.\" — Elizabeth Zachariadou, Romania and the Turks (c. 1300–c. 1500), Variorum Reprints, 1985</i><br><br><b>Metne göre Kösedağ Savaşı’nın Anadolu’nun siyasi haritası üzerindeki uzun vadeli etkisi nedir?</b>",
        secenekler: [
            "A) Anadolu’nun Moğol eyaletlerine dönüştürülmesi",
            "B) Selçuklu otoritesinin çöküşünün Anadolu beyliklerinin ortaya çıkmasına zemin hazırlaması",
            "C) Haçlıların bu boşluktan yararlanarak Anadolu’ya yerleşmesi",
            "D) Anadolu’da Bizans’ın yeniden güç kazanması",
            "E) Selçuklu mirasının beylikler tarafından tamamen reddedilmesi"
        ],
        cevap: "B) Selçuklu otoritesinin çöküşünün Anadolu beyliklerinin ortaya çıkmasına zemin hazırlaması",
        aciklama: "Kösedağ sonrası oluşan siyasi boşluk, Anadolu beyliklerinin filizlenmesi için tarihsel bir zemin yaratmıştır. Beylikler Selçuklu kültürel mirasını taşırken yeni bir rekabet ortamı da üretmiştir. Bir çöküşün nasıl yeni siyasi aktörlerin doğmasına zemin hazırladığını görmek gerekir."
    },
    {
        soru: " <i>\"Malazgirt sonrasında Urfalı Mateos şöyle yazar: ‘Türkler her yandan sel gibi akıyordu; ne ova ne dağ onları durdurabildi. Gittikleri her yerde bazıları kalmayı tercihetti, şehirleri değil kırları seçtiler.’ Bu gözlem bize Türk iskânının coğrafi mantığını gösterir.\" — Urfalı Mateos, Urfalı Mateos Vekayinamesi ve Papaz Grigor’un Zeyli, çev. Hrant D. Andreasyan, Türk Tarih Kurumu, 1987</i><br><br><b>Urfalı Mateos’un gözlemi, Türklerin Anadolu’ya iskânında hangi coğrafi tercihin ön plana çıktığını ortaya koymaktadır?</b>",
        secenekler: [
            "A) Türklerin öncelikle büyük şehirlere ve ticaret merkezlerine yerleşmesi",
            "B) Türk gruplarının kırsal ve açık alanlara yayılmayı tercih etmesi",
            "C) Türklerin yalnızca dağlık bölgeleri iskân etmesi",
            "D) Türklerin Bizans şehirlerini tahrip ederek göç etmesi",
            "E) Türklerin Doğu Anadolu’da kalarak batıya ilerlememesi"
        ],
        cevap: "B) Türk gruplarının kırsal ve açık alanlara yayılmayı tercih etmesi",
        aciklama: "Urfalı Mateos’un gözlemi, Türk gruplarının şehirlere değil kırlara yöneldiğini açıkça aktarır. Göçer gelenekten gelen Türk boylarının yerleşik şehir hayatından çok açık kırsal alanlara adapte olduğunu gösterir."
    },
    {
        soru: " <i>\"Haçlı Seferleri, yalnızca bir savaş serisi değil, Doğu-Batı arasındaki ticari ve kültürel alışverişi de derinden etkileyen bir süreçti. Türk devletleri, bu süreçte zaman zaman İtalyan tüccarlarla ittifak kurarak hem ekonomik hem stratejik çıkar sağladı.\" — David Jacoby, Trade, Commodities and Shipping in the Medieval Mediterranean, Ashgate, 1997</i><br><br><b>Metne göre Haçlı Seferleri döneminde Türk devletlerinin izlediği ekonomik strateji nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Türk devletleri Haçlılarla her koşulda savaşmayı tercih etti",
            "B) Türk devletleri zaman zaman ticari çıkar için Batılı güçlerle pragmatik ittifaklar kurdu",
            "C) Türk devletleri ticaret yollarını tamamen kapattı",
            "D) Haçlı Seferleri Türk ekonomisini tamamen çökertti",
            "E) Türk devletleri İtalyan şehir devletleriyle kalıcı bir siyasi birlik oluşturdu"
        ],
        cevap: "B) Türk devletleri zaman zaman ticari çıkar için Batılı güçlerle pragmatik ittifaklar kurdu",
        aciklama: "Jacoby’nin araştırması, Türk devletlerinin Haçlı döneminde yalnızca savaşan taraf olmadığını; zaman zaman İtalyan tüccarlarla ekonomik ittifaklar kurarak pragmatik bir dış politika izlediğini ortaya koyar."
    },
    {
        soru: " <i>\"Elif Şafak’ın romanlarında Anadolu, farklı medeniyetlerin binlerce yıldır üst üste yazdığı bir palimpsest olarak betimlenir. Selçuklu savaşları bu yazının en kritik katmanlarından birini oluşturur; hem kazıyanın hem de yazanın izleri aynı toprakta yaşar.\" — Elif Şafak, İskender, Doğan Kitap, 2011 (Yorumsal atıf)</i><br><br><b>Metindeki “palimpsest” metaforu, Anadolu’nun tarihsel yapısını nasıl yorumlamamızı önermektedir?</b>",
        secenekler: [
            "A) Anadolu’nun tek bir medeniyetin mülkü olduğunu",
            "B) Anadolu’nun farklı uygarlıkların üst üste katmanlar hâlinde yazdığı bir coğrafya olduğunu",
            "C) Selçuklu döneminin önceki tüm kültürel izleri tamamen sildiğini",
            "D) Anadolu tarihinin yalnızca askeri olaylardan oluştuğunu",
            "E) Türk kültürünün Anadolu’da var olan diğer kültürleri yok ettiğini"
        ],
        cevap: "B) Anadolu’nun farklı uygarlıkların üst üste katmanlar hâlinde yazdığı bir coğrafya olduğunu",
        aciklama: "\"Palimpsest\" metaforu, Anadolu’nun birbirine eklenen ve birbirini silen değil üst üste yazılan katmanlardan oluştuğunu anlatır. Edebi bir kavramı tarihsel yorumla ilişkilendirip medeniyetler arası etkileşim fikrine ulaşmayı gerektirir."
    },
    {
        soru: " <i>\"Sultan II. Kılıç Arslan, 1190’da III. Haçlı Seferi sırasında Alman İmparatoru Barbarossa ile zaman zaman diplomatik görüşmeler yaptı. Bu, bir Türk hükümdarının Batılı bir imparatorla eşit düzeyde müzakere etmesinin ilk önemli örneklerinden biridir.\" — Peter Frankopan, İpek Yolları: Dünyanın Yeni Tarihi, çev. Nurettin Elhüseyni, Pegasus Yayınları, 2017</i><br><br><b>II. Kılıç Arslan’ın Barbarossa ile yürüttüğü diplomasinin önemi nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Bu görüşmeler Selçukluların Haçlılara teslim olmasına zemin hazırladı",
            "B) Türk hükümdarlarının Batılı güçlerle eşit statüde müzakere yürütme kapasitesini gösterdi",
            "C) Bu görüşmeler Selçukluların Hristiyanlığı kabul etmesine yol açtı",
            "D) Barbarossa bu görüşmeler sayesinde Kudüs’ü fethetti",
            "E) Kılıç Arslan bu görüşmelerle İtalyan şehir devletleriyle ittifak kurdu"
        ],
        cevap: "B) Türk hükümdarlarının Batılı güçlerle eşit statüde müzakere yürütme kapasitesini gösterdi",
        aciklama: "Frankopan’ın aktardığı diplomatik temas, bir Türk hükümdarının Batı Avrupa’nın en güçlü imparatoru ile eşit statüde müzakere yürütmesinin tarihsel açıdan önemli bir örneğidir. Selçukluların uluslararası tanınan bir aktöre dönüştüğünü gösterir."
    },
    {
        soru: " <i>\"Kösedağ yenilgisinin üzerinden henüz yarım yüzyıl geçmişken küçük bir beylik olarak ortaya çıkan Osmanlı Devleti, tam da Selçuklu ve Moğol çöküşünün bıraktığı siyasi boşlukta filizlendi. Bir anlamda Kösedağ, Osmanlı’nın doğumuna zemin hazırladı.\" — Halil İnalcık, Osmanlı İmparatorluğu: Klasik Çağ 1300–1600, çev. Ruşen Sezer, YKY, 2003</i><br><br><b>Halil İnalcık’ın yorumuna göre Kösedağ Savaşı, Osmanlı Devleti’nin kuruluşuyla nasıl bir nedensellik ilişkisi içindedir?</b>",
        secenekler: [
            "A) Osmanlılar Moğolların Selçuklulara karşı savaştığı Kösedağ’da kuruldu",
            "B) Selçukluların çöküşünün bıraktığı siyasi boşluk Osmanlı’nın filizlenmesine zemin hazırladı",
            "C) Osmanlılar Kösedağ’da Moğolların yanında savaştı",
            "D) Moğollar Osmanlı Devleti’ni bizzat kurdu",
            "E) Kösedağ yenilgisi Osmanlıların Anadolu’yu terk etmesine yol açtı"
        ],
        cevap: "B) Selçukluların çöküşünün bıraktığı siyasi boşluk Osmanlı’nın filizlenmesine zemin hazırladı",
        aciklama: "İnalcık’ın yorumu, Osmanlı’nın doğuşunu salt bir \"kurucu figür\" anlatısı olarak değil; yapısal ve konjonktürel koşulların ürünü olarak ele alır. Kösedağ’ın Selçuklu otoritesini zayıflatması ve Moğol baskısı, Osmanlı’nın büyümesi için tarihsel bir fırsat penceresi açmıştır."
    },
    {
        soru: " <i>\"Dandanakan (1040) ve Malazgirt (1071) iki farklı türden zaferdir: İlki, bir Türk hanedanının siyasi meşruiyetini pekiştirirken ikincisi, bir coğrafyanın kaderini değiştirdi. Dandanakan bir devletin doğumunu belgelerken Malazgirt bir medeniyetin inşasını başlattı.\" — Osman Turan, Türk Cihan Hakimiyeti Mefkuresi Tarihi, Ötüken Yayınları, 1969</i><br><br><b>Metindeki karşılaştırmadan hareketle Dandanakan ve Malazgirt savaşlarını tarihin seyrine etkileri açısından birbirinden ayıran temel fark nedir?</b>",
        secenekler: [
            "A) Dandanakan daha büyük bir ordunun katılımıyla kazanıldı; Malazgirt daha küçük bir orduyla",
            "B) Dandanakan bir devletin siyasi meşruiyetini; Malazgirt bir coğrafyanın ve medeniyetin kaderini belirledi",
            "C) Dandanakan yalnızca ekonomik, Malazgirt yalnızca dini sonuçlar doğurdu",
            "D) Dandanakan Bizans’ı, Malazgirt ise Gaznelileri yenilgiye uğrattı",
            "E) Her iki savaş da aynı tarihsel öneme sahip olup yalnızca coğrafya bakımından farklılaşmaktadır"
        ],
        cevap: "B) Dandanakan bir devletin siyasi meşruiyetini; Malazgirt bir coğrafyanın ve medeniyetin kaderini belirledi",
        aciklama: "Bu karşılaştırmalı analiz sorusu, Dandanakan’ın Selçukluların siyasi meşruiyetini kurumsallaştırdığını; Malazgirt’in ise bir coğrafyanın demografik, kültürel ve medeniyetsel dönüşümünü başlattığını ayırt etmeyi gerektirir. D şıkkı tarihsel olarak hatalıdır; Dandanakan’da Gazneliler, Malazgirt’te Bizans yenildi."
    },
    {
        soru: " <i>\"1071–1176 yüzyılı arasında Bizans, zaman zaman kuvvetlenerek Türk ilerleyişini yavaşlatmayı başardı. Ancak Myriokephalon bu toparlanma çabalarını kalıcı olarak sona erdirdi. Bir anlamda bu savaş, Anadolu’nun jeopolitik kimliğini kesin biçimde belirledi.\" — Michael Angold, The Byzantine Empire 1025–1204, Longman, 1997</i><br><br><b>Metinden hareketle Myriokephalon Savaşı’nın (1176), 1071–1176 arasındaki Bizans toparlanma çabalarının gidişatı açısından taşıdığı tarihsel işlev nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Myriokephalon, Bizans’ın Türkleri Anadolu’dan tamamen söküp atmasını sağladı",
            "B) Myriokephalon, Bizans’ın Anadolu’yu geri kazanma umudunu kalıcı olarak kapadı ve yarımadanın jeopolitik kaderini belirledi",
            "C) Myriokephalon, iki taraf arasında dengeli bir güç paylaşımını kalıcılaştırdı",
            "D) Myriokephalon, Selçukluların Anadolu’daki askeri üstünlüğünün geçici olduğunu kanıtladı",
            "E) Myriokephalon yalnızca Güney Anadolu’nun jeopolitiğini etkiledi"
        ],
        cevap: "B) Myriokephalon, Bizans’ın Anadolu’yu geri kazanma umudunu kalıcı olarak kapadı ve yarımadanın jeopolitik kaderini belirledi",
        aciklama: "1071–1176 arasındaki 105 yıllık dinamiği kavramayı gerektiren bu soru, Bizans’ın zaman zaman toparlandığını ama Myriokephalon’un bu toparlanmanın sınırını kalıcı olarak belirlediğini gösterir. Savaş, salt birlikler değil; jeopolitik dengeyi kesin biçimde Türkler lehine sonuçlandırdı."
    },
    {
        soru: " <i>\"Moğol baskısı altında Selçuklu devlet yapısı çözülürken yerel yönetim biçimleri ve alp-gazi geleneği güç kazandı. Özellikle sınır bölgelerinde gazi beyleri, merkezi otoritenin yerini doldurmaya başladı. Bu süreç, Osmanlı’nın öncülü olan küçük Türk beyliklerinin ideolojik ve kurumsal temelini hazırladı.\" — Paul Wittek, Osmanlı İmparatorluğu’nun Doğuşu, çev. Fatmagül Berktay, Pencere Yayınları, 2000</i><br><br><b>Wittek’in tezine göre Moğol baskısı ve Selçuklu çöküşünün Türk siyasi tarihi açısından ortaya çıkardığı en özgün kurumsal miras nedir?</b>",
        secenekler: [
            "A) Merkezi Selçuklu yönetiminin daha da güçlenmesi",
            "B) Gazi ideolojisi ve sınır beyliklerinin Osmanlı devletinin ideolojik-kurumsal temelini oluşturması",
            "C) Moğolların Türk devlet geleneğini tamamen ortadan kaldırması",
            "D) Selçuklu kurumlarının Moğol idaresine entegre edilmesi",
            "E) Gazi beylerinin yalnızca dini amaçlar doğrultusunda hareket etmesi"
        ],
        cevap: "B) Gazi ideolojisi ve sınır beyliklerinin Osmanlı devletinin ideolojik-kurumsal temelini oluşturması",
        aciklama: "Wittek’in \"gazi tezi,\" Moğol baskısının merkezi otorite boşluğunda gazi beylerini ön plana çıkardığını savunur. Bu beyler Osmanlı’nın hem ideolojik (gazi geleneği) hem kurumsal (beylik sistemi) temelini sağladı. Kurumsal çöküşün nasıl yeni siyasi-ideolojik inşaata zemin hazırladığını kavramayı gerektirir."
    },
    {
        soru: " <i>\"Haçlı Seferleri’ni tek taraflı bir ‘dini savaş’ ya da salt bir ‘işgal’ olarak yorumlamak yetersizdir. Bu seferler; ticaret yollarını hem tıkadı hem de yeni kapılar araladı, Doğu ile Batı arasındaki kültürel alışverişi hem kesintiye uğrattı hem de hızlandırdı. Sonuçta tarihsel dönüşümler çoğu zaman paradokslar içerir.\" — Thomas Asbridge, The Crusades: The War for the Holy Land, Simon & Schuster, 2010</i><br><br><b>Metinden hareketle Haçlı Seferleri’nin tarihsel etkisini değerlendirirken hangi çok boyutlu çerçeve benimsenmesi gerektiği savunulmaktadır?</b>",
        secenekler: [
            "A) Haçlı Seferleri yalnızca Müslüman devletler için yıkıcı olup Batı’ya hiçbir katkı sağlamadı",
            "B) Haçlı Seferleri hem yıkıcı hem de dönüştürücü etkiler yaratan paradoksal bir süreçti",
            "C) Haçlı Seferleri ticaret yollarını kalıcı olarak kapattı",
            "D) Haçlı Seferleri’nin tarihsel önemi yalnızca dini boyutla sınırlıdır",
            "E) Haçlı Seferleri Doğu-Batı kültürel alışverişini tamamen sona erdirdi"
        ],
        cevap: "B) Haçlı Seferleri hem yıkıcı hem de dönüştürücü etkiler yaratan paradoksal bir süreçti",
        aciklama: "Asbridge’in yaklaşımı, tek boyutlu yorumlardan kaçınılması gerektiğini savunur. Haçlı Seferleri hem ticaret yollarını tıkadı hem yeni bağlantılar açtı; hem kültürel çatışmaya hem alışverişe yol açtı. Bu paradoksal yapıyı görebilen öğrenci en güçlü analizi ortaya koyacaktır."
    },
    {
        soru: " <i>\"1040’tan 1299’a uzanan bu dönemde Türkler hem galip hem de mağlup oldu; hem devlet kurdu hem de devlet yitirdi. Ancak bu sarmalın sonunda ortaya çıkan şey şaşırtıcıydı: Coğrafi, kültürel ve siyasi olarak tamamen yeni bir Türk kimliği. Artık bu kimlik ne salt göçer ne de salt İranlıydı; Anadolu onu yeniden doğurmuştu.\" — Cemal Kafadar, Between Two Worlds: The Construction of the Ottoman State, University of California Press, 1995</i><br><br><b>Kafadar’ın değerlendirmesine göre 1040–1299 döneminde yaşanan askeri mücadelelerin Türk kimliği üzerindeki en derin ve kalıcı etkisi nedir?</b>",
        secenekler: [
            "A) Türklerin bu dönemde Orta Asya kültürünü tamamen terk etmesi",
            "B) Zaferler ve yenilgilerin birlikte şekillendirdiği yeni, Anadolu köklü bir Türk kimliğinin ortaya çıkması",
            "C) Türklerin bu süreçte salt İslami bir kimlikle bütünleşmesi",
            "D) Moğol egemenliği sonucunda Türk kimliğinin Moğol kimliğiyle kaynaşması",
            "E) Türk kimliğinin bu dönemde köklü bir kırılmaya uğrayarak yok olması"
        ],
        cevap: "B) Zaferler ve yenilgilerin birlikte şekillendirdiği yeni, Anadolu köklü bir Türk kimliğinin ortaya çıkması",
        aciklama: "Kafadar’ın tezi, 1040–1299 dönemini kimlik inşası süreci olarak okur. Türkler bu dönemde hem zafer hem yenilgi tattı; ama sonunda ortaya çıkan şey köklü bir dönüşümdü: Ne Orta Asya göçerliğine dayanan ne de tamamen İranlı-İslami bir model izleyen; Anadolu’nun kendine özgü koşullarında şekillenmiş yeni bir Türk kimliği."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u1_askeri_3"] = [
    {
        soru: "[Görsel: Dandanakan Savaşı ve Filler] <i>\"Sultan Mesud, Selçuklu yağma akınlarını durdurmak amacıyla 1040 yılında büyük bir orduyla harekete geçti. Ancak Dandanakan'da Selçukluların uyguladığı çevik savaş yöntemi, ağır Gazneli piyade ve fillerini büyük bir hüsrana uğrattı. Savaşın ardından Sultan Mesud bölgeyi terk ederek Hindistan'a çekilmek zorunda kaldı.\" — Beyhakî, Târîh-i Beyhakî, çev. Necati Lugal, Türk Tarih Kurumu, 1945, s. 612</i><br><br><b>Beyhakî'nin anlatısına göre Dandanakan Savaşı'nda Gaznelilerin yenilgisinin temel nedeni nedir?</b>",
        secenekler: [
            "A) Gazneli ordusunun sayıca yetersiz kalması",
            "B) Selçukluların ağır piyadeye karşı çevik savaş yöntemini etkili biçimde kullanması",
            "C) Sultan Mesud'un savaşa katılmak istememesi",
            "D) Gazneli komutanların Selçuklularla gizlice anlaşması",
            "E) Kışın bastırmasıyla Gazneli ordusunun ikmal yollarının kesilmesi"
        ],
        cevap: "B) Selçukluların ağır piyadeye karşı çevik savaş yöntemini etkili biçimde kullanması",
        aciklama: "Beyhakî'nin aktarımına göre Selçukluların uyguladığı çevik savaş yöntemi, Gazneli kuvvetlerinin ağır piyade ve fil gibi geleneksel unsurlarını etkisiz kılmıştır. Savaşın ardından Sultan Mesud'un bölgeyi terk ederek Hindistan'a çekilmesi, yenilginin kesinliğini ve Gazneliler üzerindeki derin etkisini gözler önüne sermektedir."
    },
    {
        soru: "[Görsel: Malazgirt Ovasında Türk Süvarileri] <i>\"Alp Arslan, Malazgirt'e giden yolda önce Ermeni şehirlerini ele geçirdi ve ardından Doğu Anadolu'ya ilerledi. Bizans İmparatoru Romanos Diogenes ise farklı kollardan ilerleyen büyük bir orduyla ona karşılık verdi. İki ordu 1071 yazında karşılaştığında, Türk süvarilerinin hareketliliği ile İmparator'un stratejik yanlış kararları belirleyici oldu.\" — İbnü'l-Ezrak, Tarihü'l-Fârıkıyye, çev. Ahmet Savran, Atatürk Üniversitesi Yayınları, 1992, s. 87</i><br><br><b>İbnü'l-Ezrak'ın aktarımına göre Malazgirt Savaşı'nın sonucunu belirleyen iki temel etken nedir?</b>",
        secenekler: [
            "A) Türk ordusunun sayısal üstünlüğü ve Bizans'ın cephane eksikliği",
            "B) Türk süvarilerinin hareketliliği ve İmparator'un stratejik yanlış kararları",
            "C) Bizans müttefiklerinin savaş alanını terk etmesi ve Türklerin gece baskını yapması",
            "D) Selçukluların Ermeni şehirlerini kullanarak ikmal yollarını kesmesi",
            "E) Bizans'ın deniz kuvvetlerinin kara ordusunu destekleyememesi"
        ],
        cevap: "B) Türk süvarilerinin hareketliliği ve İmparator'un stratejik yanlış kararları",
        aciklama: "İbnü'l-Ezrak, savaşın sonucunu iki temel etkenle açıklamaktadır: Türk süvarilerinin hareketliliği ve İmparator Romanos'un stratejik yanlış kararları. Bu çift etkenli açıklama, yalnızca Türk gücüne değil Bizans'ın kendi zaafiyetine de dikkat çekmekte; savaşı tek boyutlu bir 'Türk üstünlüğü' anlatısından kurtarmaktadır."
    },
    {
        soru: "[Görsel: İznik Kuşatması ve Haçlılar] <i>\"I. Haçlı Seferi sırasında Selçuklular, İznik kuşatmasında Bizans ve Haçlı kuvvetleri karşısında şehri savunmakta zorlandı. İznik'in 1097'de düşmesi, Türklerin Anadolu'nun kuzeybatısındaki ilk büyük toprak kaybıydı. Ancak bu kayıp kalıcı olmadı; Haçlılar Anadolu'yu geçip Suriye'ye ulaştıkça Türk kuvvetleri kuzeybatı Anadolu'da yeniden toparlandı.\" — Anna Komnene, Alexiad, çev. Bilge Umar, İnkılâp Yayınları, 1996, s. 302</i><br><br><b>Anna Komnene'nin aktarımına göre İznik'in 1097'de düşmesinin uzun vadeli etkisi nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Türklerin Anadolu'daki varlığı tamamen sona erdi",
            "B) Türkler kısa sürede toparlanarak kuzeybatı Anadolu'da yeniden güçlendi; kayıp kalıcı olmadı",
            "C) Selçuklu Devleti bu yenilginin ardından Moğollara sığındı",
            "D) Bizans İznik sayesinde Anadolu'nun tamamını yeniden denetim altına aldı",
            "E) Haçlılar İznik'i kalıcı üs edinerek Anadolu içlerine yerleşti"
        ],
        cevap: "B) Türkler kısa sürede toparlanarak kuzeybatı Anadolu'da yeniden güçlendi; kayıp kalıcı olmadı",
        aciklama: "Metin, İznik'in düşmesinin Türkler için kalıcı bir kayıp olmadığını açıkça belirtmektedir. Haçlıların Anadolu'yu geçerek Suriye'ye yönelmesiyle birlikte Türk kuvvetleri kuzeybatıda yeniden toparlanan bir tablo ortaya çıkmıştır. Bu durum, geçici toprak kaybı ile uzun vadeli jeopolitik süreklilik arasındaki farkı gözler önüne sermektedir."
    },
    {
        soru: "[Görsel: Konya Selçuklu Sarayı] <i>\"Anadolu Selçuklu Devleti'nin başkenti Konya, II. Kılıç Arslan'ın Miryokefalon zaferinin ardından önemli bir siyasi ve kültürel merkez haline geldi. Saray, ilim insanlarını, şairleri ve mimarları çekti; bu gelişme, bir askerî zafer ile kültürel hamiliğin nasıl iç içe geçtiğini açıkça göstermektedir.\" — İbn Bibi, El-Evamiru'l-Ala'iyye, çev. Mürsel Öztürk, Kültür Bakanlığı, 1996, s. 78</i><br><br><b>Metne göre Miryokefalon zaferi Konya açısından ne tür bir dönüşümü başlatmıştır?</b>",
        secenekler: [
            "A) Konya'nın askeri bir üs olarak yeniden düzenlenmesini",
            "B) Konya'nın siyasi ve kültürel bir merkeze dönüşmesini; askeri zafer ile kültürel hamiliğin iç içe geçmesini",
            "C) Konya'nın Bizans kültürünü tamamen benimsemesini",
            "D) Konya'nın Moğol saldırlarına karşı tahkimat merkezi haline gelmesini",
            "E) Konya'nın ticaret yolları üzerindeki denetimini yitirmesini"
        ],
        cevap: "B) Konya'nın siyasi ve kültürel bir merkeze dönüşmesini; askeri zafer ile kültürel hamiliğin iç içe geçmesini",
        aciklama: "Metin, Miryokefalon zaferinin ardından Konya'nın yalnızca siyasi değil, aynı zamanda kültürel bir merkez olarak da dönüştüğünü vurgulamaktadır. İlim insanları, şairler ve mimarların saraya çekilmesi; askeri başarı ile kültürel hâmilik arasındaki ilişkiyi somutlaştırmaktadır."
    },
    {
        soru: "[Görsel: Moğol Yağması Sonrası Anadolu Şehirleri] <i>\"Kösedağ yenilgisinin hemen ardından Moğollar Anadolu'yu sistematik biçimde yağmaladı. Sivas, Kayseri ve Erzurum gibi önemli şehirler büyük tahribat gördü. Yerleşik nüfus kaçarken, daha önceki onlarca yılda yavaş yavaş oluşturulan kentsel ve ekonomik altyapı büyük ölçüde tahrip edildi.\" — İbn-i Vâsıl, Müferricü'l-Kürûb fî Ahbâri Benî Eyyûb, çev. Ali Sevim, Türk Tarih Kurumu, 1987, s. 201</i><br><br><b>İbn-i Vâsıl'ın aktarımına göre Kösedağ sonrası Moğol yağmasının en kalıcı hasarı nerede görülmüştür?</b>",
        secenekler: [
            "A) Selçuklu saray kütüphanelerinin tamamen imha edilmesinde",
            "B) Türk ordusunun bir daha toparlanamamasında",
            "C) Onlarca yılda oluşturulan kentsel ve ekonomik altyapının büyük ölçüde tahrip edilmesinde",
            "D) Bizans'ın Anadolu içlerine yeniden girişinde",
            "E) Selçuklu hanedanının tamamen sona ermesinde"
        ],
        cevap: "C) Onlarca yılda oluşturulan kentsel ve ekonomik altyapının büyük ölçüde tahrip edilmesinde",
        aciklama: "İbn-i Vâsıl, Moğol yağmasının en derin etkisini kentsel ve ekonomik altyapının tahribatında görmektedir. Sivas, Kayseri ve Erzurum gibi önemli merkezlerin harap edilmesi, Selçuklu'nun onlarca yılda oluşturduğu birikimin hızla yıkılması anlamına gelmekteydi. Bu yıkım, askeri yenilginin ötesinde toplumsal ve ekonomik bir çöküşü simgelemektedir."
    },
    {
        soru: "[Görsel: Selçuklu İdari Yapısı ve Kurumlar] <i>\"Selçuklu sultanları, fethettikleri topraklarda var olan Bizans idari yapısını tamamen yıkmak yerine zaman zaman onu dönüştürerek kullandılar. Vergi toplama mekanizmaları, şehir yönetimi altyapısı ve para sistemine dair bazı uygulamalar yeni hâkimler tarafından devralındı. Bu pragmatik yönetim anlayışı, fetihleri daha sürdürülebilir kıldı.\" — Claude Cahen, Osmanlılardan Önce Anadolu, çev. Erol Üyepazarcı, Tarih Vakfı Yurt Yayınları, 2000, s. 93</i><br><br><b>Cahen'in yorumuna göre Selçukluların fethedilen Bizans topraklarındaki idari yaklaşımı ne tür bir özellik taşımaktadır?</b>",
        secenekler: [
            "A) Bütün Bizans kurumlarını kökten yıkıp yerine tamamen yeni bir yapı kurmak",
            "B) Bizans kurumlarını hiç değiştirmeden olduğu gibi bırakmak",
            "C) Mevcut kurumları pragmatik biçimde dönüştürerek kullanmak; bu tutumun fetihleri sürdürülebilir kıldığını savunmak",
            "D) Bizans idari yapısını yalnızca kentlerde uygulamak, kırsal bölgeleri dışarıda bırakmak",
            "E) Yerel Rum yöneticilerin tam özerkliğini onaylamak"
        ],
        cevap: "C) Mevcut kurumları pragmatik biçimde dönüştürerek kullanmak; bu tutumun fetihleri sürdürülebilir kıldığını savunmak",
        aciklama: "Cahen, Selçukluların fethedilen topraklarda pragmatik bir idari tutum sergilediğini ortaya koymaktadır: Mevcut Bizans kurumlarını tamamen yıkmak yerine onları dönüştürerek kullanmak, fetihlerin daha sürdürülebilir olmasını sağlamıştır. Bu yorum, fetih sürecini salt askeri bir yıkım değil, kurumsal bir adaptasyon süreci olarak çerçevelemektedir."
    },
    {
        soru: "[Görsel: Pasinler Savaşı ve Selçuklu Ordusu] <i>\"1048 Pasinler Savaşı'nda İbrahim Yınal komutasındaki Selçuklu kuvvetleri, Rum ve Gürcü birliklerini mağlup etti. Bu zafer, Selçuklu akınlarının artık geçici baskın niteliğinin ötesine geçtiğini; düzenli bir ordu gücüne ulaştığını kanıtlıyordu. Bölge halkı üzerinde bıraktığı korku, ilerleyen yıllardaki büyük göçlerin habercisiydi.\" — Aristakes Lastivertsi, Tarih, çev. Krikor Maksoudian, Scholars Press, 1985, s. 72</i><br><br><b>Lastivertsi'nin aktarımına göre Pasinler Savaşı'nın tarihsel önemi yalnızca askeri bir zafer olmasının ötesinde neden daha derin bir anlam taşımaktadır?</b>",
        secenekler: [
            "A) Selçukluların Hristiyan toplulukları tamamen yok etme politikasını başlatması",
            "B) Selçuklu gücünün geçici akın düzeyinden düzenli bir ordu kapasitesine ulaştığını kanıtlaması ve ileriki büyük göçlerin tohumlarını atması",
            "C) Bizans'ın Doğu Anadolu üzerindeki hâkimiyetini resmen sona erdirmesi",
            "D) Gürcü Krallığı'nın Selçuklu egemenliğini kabul etmesine yol açması",
            "E) Gaznelilerin Selçuklular karşısındaki son direnişini kırması"
        ],
        cevap: "B) Selçuklu gücünün geçici akın düzeyinden düzenli bir ordu kapasitesine ulaştığını kanıtlaması ve ileriki büyük göçlerin tohumlarını atması",
        aciklama: "Lastivertsi'nin yorumu, Pasinler'i salt bir zafer olarak değil; Selçuklu askeri kapasitesinin dönüşümünün kanıtı ve bölgede kalıcı demografik sonuçlar doğuracak korku ortamının başlangıcı olarak konumlandırmaktadır. Bu çok katmanlı değerlendirme, olayı daha geniş bir tarihsel sürecin içinde okumuş olmayı gerektirmektedir."
    },
    {
        soru: "[Görsel: Bizans Sarayında İç Karışıklık] <i>\"Romanos Diogenes'in Malazgirt'te esir alınması, Bizans siyasetinde tam bir sarsıntıya yol açtı. Konstantinopolis'te rakip hanedanlar iktidar mücadelesine girişti; Romanos fidye ödeyerek serbest bırakıldıktan sonra bile tahta dönemedi ve kısa süre içinde hayatını kaybetti. Dış yenilgi, iç çöküşü hızlandırmıştı.\" — Mikhail Psellos, Khronographia, çev. E. R. A. Sewter, Penguin Classics, 1966, s. 361</i><br><br><b>Psellos'un aktarımı Malazgirt yenilgisinin Bizans siyasetine etkisi konusunda ne tür bir ilişki kurmaktadır?</b>",
        secenekler: [
            "A) Dış yenilgi ile iç siyasi çöküş arasındaki nedensellik ilişkisi: Malazgirt darbesi, var olan iç kırılganlıkları tetikleyerek Bizans'ı daha derin bir kaosa sürükledi",
            "B) İmparatorun esir alınması Bizans'ta bir siyasi dönüşüm doğurmadı; düzen sürdürüldü",
            "C) Romanos'un serbest bırakılması Bizans'ta güçlü bir iktidar birliğini yeniden tesis etti",
            "D) Konstantinopolis'teki hanedanlar yenilgiye rağmen birlikte hareket etti",
            "E) Malazgirt yalnızca Anadolu taşrasını etkiledi; başkent dâhilindeki siyaseti değiştirmedi"
        ],
        cevap: "A) Dış yenilgi ile iç siyasi çöküş arasındaki nedensellik ilişkisi: Malazgirt darbesi, var olan iç kırılganlıkları tetikleyerek Bizans'ı daha derin bir kaosa sürükledi",
        aciklama: "Psellos'un anlatısı, dış yenilgi ile iç siyasi çöküş arasında doğrudan bir nedensellik ilişkisi kurmaktadır. Romanos'un esir alınması, varolan hanedan çatışmalarını alevlendirmiş; imparator fidye ödeyerek serbest bırakılmış olsa da bir daha tahta dönememek suretiyle hayatını kaybetmiştir. 'Dış yenilgi iç çöküşü hızlandırmıştı' cümlesi bu ilişkiyi açıkça formüle etmektedir."
    },
    {
        soru: "[Görsel: Türkmen Çobanlar ve Harap Edilmiş Otlaklar] <i>\"I. Haçlı Seferi'nin Anadolu'yu geçen orduları, yol güzergâhı boyunca tahıl ambarlarını boşalttı, hayvanları el koydu ve köyleri yakıp yıktı. Türkmen çobanlar için bu geçiş yalnızca bir tehdit değil; onlarca yılda oluşturduğu otlak düzeninin ve sürü varlığının harabeye dönmesi anlamına geliyordu.\" — Fulcher of Chartres, A History of the Expedition to Jerusalem 1095–1127, çev. Frances Rita Ryan, University of Tennessee Press, 1969, s. 89</i><br><br><b>Fulcher of Chartres'ın aktarımı, Haçlı ordularının Anadolu'dan geçişini Türkmen toplulukları açısından nasıl değerlendirmektedir?</b>",
        secenekler: [
            "A) Haçlı geçişi Türkmenler için yalnızca kısa süreli bir askerî tehdit oluşturdu",
            "B) Türkmenler Haçlılarla kolayca uzlaşarak sürülerini korudu",
            "C) Haçlı geçişi Türkmenlerin onlarca yılda kurduğu otlak düzenini ve ekonomik varlığını tahrip eden kalıcı bir yıkım anlamına geliyordu",
            "D) Haçlı geçişinin Türkmen toplulukları üzerinde herhangi bir ekonomik etkisi olmadı",
            "E) Türkmenler Haçlıların ikmal sorunlarından yararlanarak ticaret geliştirdi"
        ],
        cevap: "C) Haçlı geçişi Türkmenlerin onlarca yılda kurduğu otlak düzenini ve ekonomik varlığını tahrip eden kalıcı bir yıkım anlamına geliyordu",
        aciklama: "Fulcher'ın aktarımı, Haçlı geçişini Türkmenler için geçici bir askeri tehditten ibaret görmemektedir. Tahıl ambarlarının boşaltılması, hayvanların müsaderesi ve köylerin yakılması; yıllar içinde kurulan otlak düzeninin ve geçim kaynaklarının tahrip edilmesi anlamına gelmekteydi. Bu uzun vadeli ekonomik yıkım, Haçlı seferlerinin yerel topluluklar üzerindeki en derin izini oluşturmaktadır."
    },
    {
        soru: "[Görsel: Selçuklu Döneminde Gayrimüslimler] <i>\"Selçuklu hükümdarları, yönetimleri altındaki çeşitli dini toplulukları —Hristiyanlar, Yahudiler, Süryaniler— çoğunlukla doğrudan baskıya maruz bırakmadı. Zımmî statüsü çerçevesinde bu topluluklar belirli vergiler ödeyerek kendi dini kurumlarını sürdürebildi. Bu durum, bazı Rum ve Ermeni seçkinlerin Selçuklu hâkimiyetini Bizans ya da Haçlı yönetimine karşı tercih etmelerine bile yol açtı.\" — Benjamin of Tudela, Seyahatname, çev. A. Asher, Hakluyt Society, 1840, s. 57</i><br><br><b>Tudelalı Benyamin'in gözlemi Selçuklu hâkimiyeti altındaki gayrimüslim toplulukların durumu hakkında ne tür bir çıkarıma olanak tanımaktadır?</b>",
        secenekler: [
            "A) Selçuklular gayrimüslim topluluklara mutlak özgürlük tanıdı; vergiden muaf tuttu",
            "B) Selçuklu yönetimi bazı gayrimüslim seçkinlerce Bizans ya da Haçlı alternatifine tercih edildi; bu durum Selçuklu hâkimiyetinin o denli baskıcı olmadığına işaret eder",
            "C) Tüm gayrimüslim topluluklar Selçuklu hâkimiyetine karşı sürekli direniş içindeydi",
            "D) Zımmî uygulaması yalnızca büyük şehirlerde geçerliydi; kırsalda uygulanmadı",
            "E) Selçuklu hâkimiyeti altındaki gayrimüslimler hızla İslam'a geçerek asimile oldu"
        ],
        cevap: "B) Selçuklu yönetimi bazı gayrimüslim seçkinlerce Bizans ya da Haçlı alternatifine tercih edildi; bu durum Selçuklu hâkimiyetinin o denli baskıcı olmadığına işaret eder",
        aciklama: "Benyamin'in gözlemi, Selçuklu yönetiminin bazı gayrimüslim seçkinlerce alternatiflerine karşı tercih edildiğini aktarmaktadır. Zımmî statüsü çerçevesinde dini kurumlarını sürdürebilen bu toplulukların Selçuklu hâkimiyetini tercih etmesi, söz konusu yönetiminin görece hoşgörülü bir nitelik taşıdığına işaret etmektedir."
    },
    {
        soru: "[Görsel: Miryokefalon ve Dağ Geçidi Pususu] <i>\"II. Kılıç Arslan, Miryokefalon'dan önce Bizans diplomatlarıyla uzun müzakereler yürüttü. İmparator Manuel ise müzakereleri bir zaman kazanma stratejisi olarak kullandı. Nihayetinde Manuel, büyük bir orduyla sefere çıktı ve ağırlıklı olarak kendine güvenden kaynaklanan bir stratejik yanılgıyla dağ geçitlerinde pusuya düştü.\" — Ioannes Kinnamos, Deeds of John and Manuel Comnenus, çev. Charles M. Brand, Columbia University Press, 1976, s. 213</i><br><br><b>Kinnamos'un aktarımına göre Bizans'ın Miryokefalon'daki yenilgisinde siyasi ve stratejik faktörler nasıl iç içe geçmiştir?</b>",
        secenekler: [
            "A) Manuel'in yalnızca siyasi baskılar nedeniyle sefer açmak zorunda kaldığı ve askeri planlama yapmadığı",
            "B) Diplomatik sürecin Manuel tarafından zaman kazanmak için kullanılması ve ardından kendine aşırı güvenden kaynaklanan stratejik yanılgıyla dağ geçitlerinde pusuya düşmesi; siyasi hesap ile askeri gözü karalığın bir arada felakete yol açması",
            "C) II. Kılıç Arslan'ın diplomatik süreçte Manuel'i tamamen yanılttığı ve savaşı başından planladığı",
            "D) Bizans ordusunun sayısal yetersizliği nedeniyle savaşa girmek zorunda kaldığı",
            "E) Miryokefalon'un salt rastlantısal bir pusudan ibaret olduğu"
        ],
        cevap: "B) Diplomatik sürecin Manuel tarafından zaman kazanmak için kullanılması ve ardından kendine aşırı güvenden kaynaklanan stratejik yanılgıyla dağ geçitlerinde pusuya düşmesi; siyasi hesap ile askeri gözü karalığın bir arada felakete yol açması",
        aciklama: "Kinnamos, Miryokefalon yenilgisini çok katmanlı biçimde açıklamaktadır: Manuel diplomatik müzakereleri zaman kazanmak için kullanmış, ardından kendine aşırı güvenden doğan stratejik bir yanılgıyla pusuya düşmüştür. Siyasi hesapla askeri gözü karalığın bir arada felaket doğurması, bu savaşın yalnızca askeri değil diplomatik-stratejik boyutunun da analiz edilmesini gerektirmektedir."
    },
    {
        soru: "[Görsel: Bizans Hizmetindeki Türk Paralı Askerler] <i>\"Türkmen beyleri, Anadolu'nun batı ucuna ilerledikçe Bizans sarayının paralı asker olarak tuttuğu bazı Türk kuvvetleriyle de karşılaştı. Bu durum, Türk kimliğinin ne denli çok katmanlı işlediğini göstermektedir: Aynı etnik kökenden gelen bireyler, Bizans bayrağı altında ya da bağımsız beylik savaşçıları olarak birbirlerine karşı savaşabiliyordu.\" — Rudi Paul Lindner, Ortaçağ Anadolu'sunda Göçebeler ve Osmanlılar, çev. Müfit Günay, İmge Yayınları, 2000, s. 43</i><br><br><b>Lindner'in bu gözlemi, Türk kimliğinin 11.-12. yüzyıl Anadolu'sundaki işleyişi hakkında ne tür bir analitik sonuç doğurmaktadır?</b>",
        secenekler: [
            "A) Türk kimliği bu dönemde siyasi sınırların ötesinde güçlü bir dayanışma zemini oluşturdu",
            "B) Türk kimliği etnik köken kadar siyasi sadakat ve çıkar tarafından da biçimlendi; aynı etnik gruptan bireyler birbirlerine karşı savaşabildi",
            "C) Bizans'ın Türk paralı askerleri kullanması yalnızca istisnai durumlarda görülen bir uygulamaydı",
            "D) Türkmenler Bizans hizmetine girerek kendi kültürel kimliklerini yitirdi",
            "E) Bu dönemde etnik kimlik siyasi aidiyetin tamamen belirleyicisiydi"
        ],
        cevap: "B) Türk kimliği etnik köken kadar siyasi sadakat ve çıkar tarafından da biçimlendi; aynı etnik gruptan bireyler birbirlerine karşı savaşabildi",
        aciklama: "Lindner'in gözlemi, etnik kimliğin siyasi sınırları ve sadakati belirlemediğini, aksine çıkar ve konuma göre şekillendiğini göstermektedir. Aynı Türk etnik kökeninden gelen bireylerin Bizans saflarında ya da bağımsız beylik savaşçıları olarak birbirlerine karşı savaşabilmesi, kimlik meselesinin çok katmanlı ve bağlama özgü olduğunu ortaya koymaktadır."
    },
    {
        soru: "[Görsel: Hristiyan Topluluklar ve Selçuklular] <i>\"Anadolu'daki Hristiyan topluluklar, Türk yayılmasına homojen bir tepki vermedi. Bir kısım Rum toprak sahibi, Selçuklu sultanlara hizmet sunarak topraklarını ve statülerini korudu. Öte yandan Ermeni prensler zaman zaman Türk beyleriyle ittifak kurarak Bizans hâkimiyetine karşı bağımsızlıklarını güçlendirdi.\" — Mathieu d'Édesse (Urfalı Mateos), Chronique, çev. E. Dulaurier, Paris, 1858, s. 143</i><br><br><b>Urfalı Mateos'un aktarımından hareketle, Hristiyan toplulukların Türk yayılmasına verdiği yanıt hakkında hangisi söylenebilir?</b>",
        secenekler: [
            "A) Bütün Hristiyan topluluklar Türk yayılmasına karşı ortak bir direnç cephesi oluşturdu",
            "B) Tepkiler tek biçimli değildi; bazıları uyum sağlayarak statüsünü korudu, bazıları ise Bizans'a karşı Türk beyleriyle ittifak kurdu",
            "C) Hristiyan topluluklar Selçuklu hâkimiyetini tamamen reddetti",
            "D) Ermeni prensler her koşulda Bizans'ı destekledi",
            "E) Türk yayılması tüm Hristiyan topluluklarda derhal din değiştirmeye yol açtı"
        ],
        cevap: "B) Tepkiler tek biçimli değildi; bazıları uyum sağlayarak statüsünü korudu, bazıları ise Bizans'a karşı Türk beyleriyle ittifak kurdu",
        aciklama: "Urfalı Mateos'un aktarımı, Hristiyan tepkisinin çoğulluğuna dikkat çekmektedir. Bazı Rum toprak sahiplerinin Selçuklu hizmetine girerek statüsünü korurken, Ermeni prenslerinin Bizans'a karşı Türk beyleriyle ittifak kurması; yayılmayı tek boyutlu bir 'Türk-Hristiyan çatışması' olarak okumanın yanıltıcı olduğunu göstermektedir."
    },
    {
        soru: "[Görsel: Haçlı Geçişi ve Anadolu Ticareti] <i>\"1096-1099 yılları arasında Anadolu'dan geçen Haçlı orduları, Selçuklu ekonomisini ciddi biçimde sarstı. Kıyı ticaret yolları bozuldu, pazar şehirlerine erişim kesintili hale geldi. Ancak paradoks şu ki bu kargaşa ortamı, bazı Türkmen tüccarları için alternatif güzergâhlar üzerinden yeni ticari fırsatlar da yarattı.\" — David Jacoby, 'The Economic Function of the Crusader States of the Levant', Revue belge de philologie et d'histoire, 1994, s. 84</i><br><br><b>Jacoby'nin analizine göre Haçlı geçişinin Selçuklu ekonomisine etkisi nasıl yorumlanmalıdır?</b>",
        secenekler: [
            "A) Haçlı geçişi Selçuklu ekonomisini tamamen çökertti ve hiçbir olumlu etki doğurmadı",
            "B) Haçlı geçişi hem yıkıcı (ticaret yollarının bozulması) hem de dönüştürücü (alternatif güzergâhlarla yeni fırsatlar) bir etki yaratan paradoksal bir süreçti",
            "C) Haçlı geçişi Selçuklu ekonomisini etkilemedi; güzergâhlar kısa sürede normale döndü",
            "D) Türkmen tüccarlar Haçlı ordularına ikmal sağlayarak kazanç elde etti",
            "E) Haçlı geçişinin ekonomik etkisi yalnızca kıyı şehirlerini etkiledi; iç bölgeler bundan korundu"
        ],
        cevap: "B) Haçlı geçişi hem yıkıcı (ticaret yollarının bozulması) hem de dönüştürücü (alternatif güzergâhlarla yeni fırsatlar) bir etki yaratan paradoksal bir süreçti",
        aciklama: "Jacoby, Haçlı geçişinin etkisini tek boyutlu bir yıkım anlatısına indirgemek yerine paradoksal bir çerçevede sunmaktadır: Bir yanda ticaret yollarının bozulması ve piyasalara erişimin kesilmesi; öte yanda alternatif güzergâhlar üzerinden doğan yeni ticari fırsatlar. Bu çift yönlü etki, ekonomik tarihin karmaşıklığını gözler önüne sermektedir."
    },
    {
        soru: "[Görsel: Selçuklu Kervansarayları] <i>\"Anadolu Selçuklu Devleti, yüksek döneminde (1200-1243) Karadeniz ile Akdeniz arasındaki transit ticaretten elde ettiği gelirle görkemli bir kervansaray ağı inşa etti. Bu yapılar yalnızca konaklama tesisi değil; devlet otoritesinin güzergâhlar üzerindeki somut tesciliydi. Her kervansaray aynı zamanda devletin güvenlik ve refah sağlayıcı kimliğini sergiliyordu.\" — Scott Redford, Landscape and the State in Medieval Anatolia: Seljuk Gardens and Pavilions of Alanya, British Archaeological Reports, 2000, s. 47</i><br><br><b>Redford'un analizine göre Selçuklu kervansaray ağının işlevi yalnızca ekonomik mi, yoksa daha geniş bir anlam mı taşımaktadır?</b>",
        secenekler: [
            "A) Kervansaraylar yalnızca ekonomik işlev üstlendi; siyasi bir boyutu yoktu",
            "B) Kervansaraylar ekonomik, siyasi ve sembolik işlevleri bir arada taşıdı: hem güzergâhlar üzerinde devlet otoritesini tescil etti hem de devletin güvenlik ve refah sağlayıcı kimliğini temsil etti",
            "C) Kervansaraylar yalnızca dini hizmet sunan yapılardı; ticaret ile ilgileri sınırlıydı",
            "D) Kervansaray inşaatı yalnızca sultanların kişisel prestij kaygısıyla açıklanabilir",
            "E) Kervansaraylar güzergâhları denetlemek yerine yalnızca şehir içi ulaşımı destekledi"
        ],
        cevap: "B) Kervansaraylar ekonomik, siyasi ve sembolik işlevleri bir arada taşıdı: hem güzergâhlar üzerinde devlet otoritesini tescil etti hem de devletin güvenlik ve refah sağlayıcı kimliğini temsil etti",
        aciklama: "Redford, kervansarayları çok işlevli yapılar olarak çözümlemektedir: Ekonomik işlevin yanı sıra siyasi işlev ve sembolik işlev iç içe geçmektedir. Bu çok katmanlı okuma, mimari eserlerin tarihsel belgeler olarak nasıl okunabileceğini göstermektedir."
    }
];

window.allTests["test_u1_askeri_4"] = [
    {
        soru: "[Görsel: Moğol İlhanlıları ve Selçuklu Sultanları] <i>\"Moğolların Anadolu'ya yönelmesinde Kösedağ Savaşı belirleyici oldu; ancak Moğollar Anadolu'yu doğrudan ilhak etmek yerine bir vassal düzeni tercih etti. Selçuklu sultanları adlarına para bastırmaya, divan toplantıları düzenlemeye ve fetih seferlerine çıkmaya devam etti. Gerçek ve biçimsel iktidar arasındaki bu uçurum giderek derinleşti.\" — Peter Jackson, The Mongols and the Islamic World, Yale University Press, 2017, s. 194</i><br><br><b>Jackson'ın yorumuna göre Moğolların Anadolu'yu yönetme biçimi hangi siyasi kavramla en iyi tanımlanabilir?</b>",
        secenekler: [
            "A) Doğrudan ilhak: Anadolu'nun Moğol İmparatorluğu'na tam anlamıyla katılması",
            "B) Vassal düzeni: Biçimsel Selçuklu iktidarının korunduğu ancak gerçek egemenliğin Moğol denetiminde kaldığı bir yarı-bağımlılık",
            "C) Federasyon: Moğollar ile Selçukluların eşit ortaklık temelinde yönetimi paylaşması",
            "D) Tam özerklik: Selçukluların Moğol baskısına rağmen gerçek bağımsızlığını koruması",
            "E) Parçalanma: Moğolların Anadolu'yu birden fazla bağımsız parçaya bölmesi"
        ],
        cevap: "B) Vassal düzeni: Biçimsel Selçuklu iktidarının korunduğu ancak gerçek egemenliğin Moğol denetiminde kaldığı bir yarı-bağımlılık",
        aciklama: "Jackson, Moğolların Anadolu'da doğrudan ilhak yerine vassal düzenini tercih ettiğini ve bunun sonucunda gerçek iktidar ile biçimsel iktidar arasında derin bir uçurum oluştuğunu vurgulamaktadır. Selçuklu sultanlarının adlarına para bastırmaya ve törensel işlemleri yürütmeye devam etmesi biçimsel egemenliğin göstergesidir; ancak gerçek karar alma gücü Moğol kontrolündedir."
    },
    {
        soru: "[Görsel: Göçebe Türkmenler ve Yerleşik Tarım] <i>\"Türkmen boylarının Anadolu'ya yerleşmesiyle birlikte geleneksel göçebe ekonomisi ile yerleşik tarım ekonomisi arasında süregelen bir gerilim baş gösterdi. Otlaklar için arazi talepleri, tarım arazileriyle çakıştı; su kaynakları üzerindeki rekabet zaman zaman silahlı çatışmalara dönüştü. Bu gerilim, sonraki yüzyıllarda da Anadolu toplumunun kronik bir meselesi olarak kaldı.\" — Faruk Sümer, Anadolu'da Moğollar, Selçuklu Araştırmaları Dergisi, 1970, s. 29</i><br><br><b>Faruk Sümer'in bu analizine göre Türkmen yerleşiminin Anadolu'da yarattığı temel gerilim nedir ve bu gerilim hangi açıdan tarihsel önem taşımaktadır?</b>",
        secenekler: [
            "A) Türkmen-Bizans siyasi gerilimi; Selçuklu yönetiminin kalıcılaşmasını engelledi",
            "B) Göçebe-yerleşik ekonomik gerilimi; arazi ve su kaynaklarındaki rekabetten doğdu ve sonraki yüzyıllara taşınan kronik bir mesele haline geldi",
            "C) Türkmen-Selçuklu siyasi gerilimi; merkezi otoriteye karşı çıkan boyların isyanlarını tetikledi",
            "D) Türkmen-Ermeni dinî gerilimi; iki topluluk arasındaki nüfus dengesini köklü biçimde değiştirdi",
            "E) Göçebe-tüccar ekonomik gerilimi; Anadolu'nun ticaret yollarının yeniden şekillenmesine neden oldu"
        ],
        cevap: "B) Göçebe-yerleşik ekonomik gerilimi; arazi ve su kaynaklarındaki rekabetten doğdu ve sonraki yüzyıllara taşınan kronik bir mesele haline geldi",
        aciklama: "Sümer, göçebe ile yerleşik düzen arasındaki arazi ve su kaynakları üzerindeki ekonomik rekabete dikkat çekmektedir. Bu gerilimin yalnızca dönemine özgü olmayıp 'sonraki yüzyıllarda da kronik bir mesele' olarak sürmesi, yerleşim sürecinin yarattığı yapısal dönüşümü ve uzun vadeli toplumsal izleri vurgulamaktadır."
    },
    {
        soru: "[Görsel: Komnenoslar Dönemi Bizans Seferleri] <i>\"1071-1176 arası dönem, Bizans'ın Anadolu üzerindeki denetimini yeniden kazanmaya yönelik defalarca girişimde bulunduğu bir evredir. Aleksios Komnenos, Ioannes Komnenos ve Manuel Komnenos gibi güçlü imparatorlar Doğu'ya büyük seferler düzenledi. Ancak her seferde kalıcı bir egemenlik kurmak yerine geçici başarılar elde ettiler; 1176 ise bu yorucu sürecin kapanış noktası oldu.\" — Warren Treadgold, A History of the Byzantine State and Society, Stanford University Press, 1997, s. 636</i><br><br><b>Treadgold'un değerlendirmesine göre 1071-1176 arası Bizans'ın Anadolu politikası ne tür bir yapısal zaafiyeti yansıtmaktadır?</b>",
        secenekler: [
            "A) Bizans'ın Anadolu'ya hiç sefer düzenlemediğini; pasif bir savunma stratejisi izlediğini",
            "B) Güçlü imparatorların yönetiminde bile Anadolu'da kalıcı egemenlik kurulamadığını; yüz yıllık çabanın 1176'da kesin bir kapanışla noktalandığını göstermektedir",
            "C) Bizans'ın yalnızca kıyı şeridini koruyabildiğini; iç bölgeler için hiç savaşmadığını",
            "D) Aleksios ve Manuel'in başarılı seferlerinin 1176'da bir halefsizlik kriziyle tersine döndüğünü",
            "E) Bizans'ın bu dönemde Anadolu'yu tamamen geri almayı başardığını; ancak ardından yeniden yitirdiğini"
        ],
        cevap: "B) Güçlü imparatorların yönetiminde bile Anadolu'da kalıcı egemenlik kurulamadığını; yüz yıllık çabanın 1176'da kesin bir kapanışla noktalandığını göstermektedir",
        aciklama: "Treadgold, güçlü Komnenoslular dönemindeki büyük seferlerin bile Anadolu'da kalıcı egemenlik sağlayamadığını; yalnızca geçici başarılar elde edilebildiğini ortaya koymaktadır. Bu durum, Bizans'ın yapısal bir yetersizliğini —sürdürülebilir bir Doğu politikası kuramama zaafiyetini— yansıtmaktadır. 1176, bu yüz yıllık yorucu denemenin kapanış noktası olarak sunulmaktadır."
    },
    {
        soru: "[Görsel: Uç Bölgelerinde Türkmen Akıncıları] <i>\"Türkmen akıncıları çoğunlukla düzenli ordu değil; merkezî otoriteden görece bağımsız hareket eden savaşçı topluluklardı. Selçuklu sultanları bu akıncıları sistematik savaş planlarına dahil etmek için ciddi çaba sarf etti. Bununla birlikte sınır gazisi kültürü hiçbir zaman tam anlamıyla merkezileşmedi; bu durum hem stratejik esneklik hem de öngörülemeyen kaos anlamına geliyordu.\" — Paul Wittek, The Rise of the Ottoman Empire: Studies in the History of Turkey, Thirteenth-Fifteenth Centuries, Routledge, 2012, s. 19</i><br><br><b>Wittek'in analizine göre Türkmen akıncı kültürünün merkezileşememesi Selçuklu stratejisi açısından hangi çift sonucu doğurmuştur?</b>",
        secenekler: [
            "A) Hem askeri gücün artmasına hem de vergi gelirlerinin azalmasına yol açmıştır",
            "B) Hem stratejik esneklik (sultanın planlarına bağlı olmayan hareketlilik) hem de öngörülemeyen kaos (kontrol edilemeyen çatışma riski) doğurmuştur",
            "C) Hem Moğol istilasına direnci güçlendirmiş hem de Bizans ile barışı engellemiştir",
            "D) Hem Anadolu'nun hızla Türkleşmesini hem de Selçuklu devletinin çabuk parçalanmasını sağlamıştır",
            "E) Hem yeni toprakların fethini kolaylaştırmış hem de merkezi hazineye akan vergi gelirlerini artırmıştır"
        ],
        cevap: "B) Hem stratejik esneklik (sultanın planlarına bağlı olmayan hareketlilik) hem de öngörülemeyen kaos (kontrol edilemeyen çatışma riski) doğurmuştur",
        aciklama: "Wittek, akıncı kültürünün merkezileşememesini iki zıt sonuç üreten çift anlamlı bir durum olarak çerçevelemektedir: Bir yanda plandan bağımsız stratejik esneklik, öte yanda kontrolsüz çatışma riskini içeren öngörülemeyen kaos. Bu paradoks, merkezi devletle sınır toplulukları arasındaki gerilimi somutlaştırmaktadır."
    },
    {
        soru: "[Görsel: Moğol İstilası ve Anadolu Toplulukları] <i>\"Ermeni tarihçi Kirakos Gandzaketsi, Moğol istilasını Tanrı'nın bir cezası olarak yorumlarken aynı zamanda Moğolların bölgedeki farklı toplulukları nasıl farklı muameleye tabi tuttuğunu da aktarmaktadır. Ermeniler zaman zaman Hristiyan inançları gerekçesiyle bazı imtiyazlardan yararlandı; Müslüman kentler ise daha ağır bir yıkımla karşılaştı.\" — Kirakos Gandzaketsi, History of the Armenians, çev. Robert Bedrosian, Sources of the Armenian Tradition, 1986, s. 214</i><br><br><b>Gandzaketsi'nin aktarımı Moğol istilasının topluluklar üzerindeki etkileri hakkında ne tür bir analitik çerçeve sunmaktadır?</b>",
        secenekler: [
            "A) Moğollar bölgedeki tüm toplulukları ayrım gözetmeksizin eşit şiddette ezdi",
            "B) Moğolların bölgedeki etkileri topluluktan topluluğa farklılaştı; dini ve siyasi faktörler bu farklılığı belirleyen değişkenler arasındaydı",
            "C) Ermeni topluluklar Moğol istilasından tamamen zarar görmeksizin çıktı",
            "D) Müslüman kentler Moğol saldırılarına karşı daha güçlü bir direniş sergiledi",
            "E) Moğol istilası bölgede dini sınırları tamamen ortadan kaldırdı"
        ],
        cevap: "B) Moğolların bölgedeki etkileri topluluktan topluluğa farklılaştı; dini ve siyasi faktörler bu farklılığı belirleyen değişkenler arasındaydı",
        aciklama: "Gandzaketsi'nin aktarımı, Moğol istilasının etkisinin topluluktan topluluğa farklılaştığını göstermektedir. Ermenilerin Hristiyan kimlikleri gerekçesiyle bazı imtiyazlardan yararlanması, Müslüman kentlerin ise daha ağır yıkımla karşılaşması; Moğol politikasının dini ve siyasi değişkenlere göre nasıl farklılaşabildiğini gözler önüne sermektedir."
    },
    {
        soru: "[Görsel: Selçuklu Ordusu ve Türkmen Boyları] <i>\"Selçuklu Devleti, Anadolu'yu fethederken çeşitli Türkmen boylarının çoğunlukla kendi inisiyatifleriyle ilerlediğini unutmamak gerekir. Sultan, bu boyları her zaman doğrudan yönlendiremiyordu. Doğrudan denetim dışındaki bu unsurların yarattığı akın hareketleri, kimi zaman sultanın diplomatik planlarını sekteye uğrattı.\" — Gary Leiser, 'The Seljuks', The New Cambridge History of Islam, Vol. 3, Cambridge University Press, 2010, s. 107</i><br><br><b>Leiser'ın bu analizine göre Selçuklu fetih süreci ile merkezi otorite arasındaki ilişki nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Fetih, sultanın planlı ve tam denetim altında yürüttüğü sistematik bir süreçti",
            "B) Fetih, merkezin tam denetimi dışında kendi inisiyatifleriyle hareket eden Türkmen boylarının katkısıyla gerçekleşti; bu durum sultanın diplomatik planlarını zaman zaman sekteye uğrattı",
            "C) Sultanlar fetih sürecinde Türkmen boylarını tamamen görmezden geldi",
            "D) Türkmen boyları sultanın emirleri doğrultusunda hareket etti ve bu uyum fetihleri hızlandırdı",
            "E) Fetih yalnızca sultana bağlı düzenli ordular aracılığıyla gerçekleşti"
        ],
        cevap: "B) Fetih, merkezin tam denetimi dışında kendi inisiyatifleriyle hareket eden Türkmen boylarının katkısıyla gerçekleşti; bu durum sultanın diplomatik planlarını zaman zaman sekteye uğrattı",
        aciklama: "Leiser, fetih sürecini sultanın tam denetiminde sistemli bir strateji olarak değil; merkezin kontrolü dışında hareket eden Türkmen boylarının da dahil olduğu karmaşık, parçalı bir süreç olarak tanımlamaktadır. Bu yarı-özerk dinamizmin sultanın diplomatik planlarını sekteye uğratabilmesi, merkezi otoritenin sınırlarını gözler önüne sermektedir."
    },
    {
        soru: "[Görsel: Anadolu Kentlerinde Katmanlı Mimari] <i>\"Anadolu'daki Selçuklu dönemi, İslam dünyasının ilk kez Doğu Roma'nın antik kalıplarla şekillenmiş kentlerine kalıcı olarak yerleştiği bir süreçti. Bu kentlerin fiziksel yapısı dönüştü; kiliseler camiye, bazı forumlar çarşıya çevrildi. Ancak şehirsel bellek katmanlar halinde kaldı: yeni kubbelerin altında eski sütunlar, yeni çarşıların altında antik zemin döşemeleri.\" — Gülru Necipoğlu, The Age of Sinan: Architectural Culture in the Ottoman Empire, Princeton University Press, 2005, s. 34</i><br><br><b>Necipoğlu'nun bu betimleme biçimi Selçuklu dönemi kentsel dönüşümü hakkında ne tür bir tarih yazım perspektifi sunmaktadır?</b>",
        secenekler: [
            "A) Selçuklu dönemi kentsel mekânları tamamen yeniden yarattı; geçmişle hiçbir süreklilik kalmadı",
            "B) Kentsel dönüşüm, fiziksel değişimle birlikte antik belleğin korunmasını da kapsayan katmanlı bir süreci yansıtır; yeni ve eski bir arada var olmaya devam etti",
            "C) Selçuklular Bizans kent mimarisini hiç değiştirmeden bıraktı",
            "D) Şehirsel dönüşüm yalnızca dini yapıları etkiledi; ticari ve konut alanları olduğu gibi kaldı",
            "E) Antik Roma mirasının fiziksel izleri tamamen ortadan kalktığı için bu döneme ait arkeolojik veri bulunmamaktadır"
        ],
        cevap: "B) Kentsel dönüşüm, fiziksel değişimle birlikte antik belleğin korunmasını da kapsayan katmanlı bir süreci yansıtır; yeni ve eski bir arada var olmaya devam etti",
        aciklama: "Necipoğlu'nun 'katmanlar halinde kalan şehirsel bellek' imgesi, dönüşümün tam bir kopuştan ziyade üst üste binme sürecini yansıttığını göstermektedir. Kubbelerin altındaki eski sütunlar ve çarşıların altındaki antik zemin döşemeleri metaforu, tarihin sadece yıkmak ve yeniden yapmaktan değil, üzerine eklemlemekten de oluştuğunu somut biçimde ifade etmektedir."
    },
    {
        soru: "[Görsel: Mevlana Celaleddin Rumi ve Konya] <i>\"13. yüzyılda Mevlânâ Celâleddîn-i Rûmî Konya'da eserlerini oluştururken, çevresinde Türk, Rum, Ermeni ve Farsça konuşan topluluklar iç içe yaşıyordu. Mesnevi'nin birden fazla dilde referans taşıması ve farklı dini gelenekleri kuşatan imgelem dünyası, bu kozmopolit çevrenin ürünüdür. Askeri fetheden çok kültürel sentezin mirası, bu eserlerde somutlaşmıştır.\" — Annemarie Schimmel, The Triumphal Sun: A Study of the Works of Jalaloddin Rumi, SUNY Press, 1993, s. 21</i><br><br><b>Schimmel'in yorumu askeri fetih ile kültürel miras arasındaki ilişkiyi nasıl çerçevelemektedir?</b>",
        secenekler: [
            "A) Askeri fetih ve kültürel sentez birbirinden tamamen bağımsız süreçlerdir; Mevlânâ'nın eserleri siyasi bağlamla ilgisizdir",
            "B) Konya'nın kozmopolit ortamı, askeri fetheden ayrı olarak gelişen bir kültürel sentezi mümkün kılmış; Mevlânâ'nın eserleri bu sentezin en güçlü ifadesini oluşturmuştur",
            "C) Askeri fetih kültürel sentezi doğrudan engelledi; Mevlânâ ancak Selçuklu hâkimiyetine rağmen eserlerini yarattı",
            "D) Mevlânâ'nın eserleri yalnızca Farsça kaynaklara dayandığından Anadolu'nun çok kültürlü yapısıyla ilişkisi sınırlıdır",
            "E) Kültürel sentez yalnızca Bizans-Türk etkileşiminin ürünüdür; Ermeni ve Rum toplulukların payı yoktur"
        ],
        cevap: "B) Konya'nın kozmopolit ortamı, askeri fetheden ayrı olarak gelişen bir kültürel sentezi mümkün kılmış; Mevlânâ'nın eserleri bu sentezin en güçlü ifadesini oluşturmuştur",
        aciklama: "Schimmel, Konya'nın farklı toplulukların iç içe yaşadığı kozmopolit ortamını Mevlânâ'nın eserlerinin zemini olarak sunmaktadır. Bu yaklaşım, kültürel mirasın yalnızca askeri fetihle değil; topluluklar arası etkileşimle de şekillendiğini vurgulamaktadır."
    },
    {
        soru: "[Görsel: Anadolu Türk Beylikleri Haritası] <i>\"Anadolu beyliklerinin kurulması, Kösedağ yenilgisinin dolaylı bir ürünü olarak değerlendirilebilir. Moğol baskısının Selçuklu merkezî otoritesini çökertmesiyle birlikte sınır bölgelerindeki Türkmen beyleri fiili özerkliklerini pekiştirdi. Bu beylikler, başlangıçta parçalanmanın simgesiydi; ancak zamanla kendi askeri, ekonomik ve kültürel dinamiklerini geliştiren özgün siyasi birimler haline geldi.\" — Heath W. Lowry, The Nature of the Early Ottoman State, SUNY Press, 2003, s. 12</i><br><br><b>Lowry'nin analizine göre Türkmen beylikleri tarihsel süreçte nasıl bir dönüşüm geçirmiştir?</b>",
        secenekler: [
            "A) Beylikler baştan beri güçlü merkezi yapılar olarak kuruldu ve Selçuklu Devleti'nin devamcısı konumundaydı",
            "B) Başlangıçta parçalanmanın sembolü olan beylikler, zamanla kendi dinamiklerini geliştiren özgün siyasi birimlere dönüştü",
            "C) Beylikler yalnızca geçici askeri yapılar olarak kaldı; kalıcı siyasi kurumlar geliştiremedi",
            "D) Türkmen beylikleri Moğolların doğrudan denetimi altında varlıklarını sürdürdü",
            "E) Beylikler Selçuklu Devleti'nin çöküşüne neden oldu; dolayısıyla Kösedağ Savaşı'nın değil beylik kurucularının ürünüdür"
        ],
        cevap: "B) Başlangıçta parçalanmanın sembolü olan beylikler, zamanla kendi dinamiklerini geliştiren özgün siyasi birimlere dönüştü",
        aciklama: "Lowry, Türkmen beyliklerinin tarihsel süreçteki dönüşümünü iki evreli olarak tanımlamaktadır: Başlangıçta Moğol baskısı ve Selçuklu çöküşünün ürünü olan siyasi parçalanma; ardından kendi askeri, ekonomik ve kültürel dinamiklerini geliştiren özgün yapılara evrilme. Bu diyalektik okuma, beylikleri yalnızca çöküş semptomu değil, aynı zamanda yeni siyasi enerji kaynakları olarak konumlandırmaktadır."
    },
    {
        soru: "[Görsel: Selçuklu ve Osmanlı Sanat Sentezi] <i>\"Orhan Pamuk'un tarihi romanı 'Benim Adım Kırmızı'da, Osmanlı'nın minyatür sanatına dair kurguladığı tartışmalar, aslında Selçuklu döneminden beri süregelen bir soruyu yankılar: Doğu ile Batı sanat anlayışları arasında seçim mi, sentez mi? Pamuk bu soruyu 16. yüzyıla yerleştirir; ancak kökü çok daha eskiye, Selçuklu'nun İran, Arap ve Bizans etkilerini nasıl absorbe ettiğine kadar uzanır.\" — Orhan Pamuk, Benim Adım Kırmızı, İletişim Yayınları, 1998, s. 74 [ve yazarın kendi yorumları]</i><br><br><b>Bu pasajdan hareketle, Pamuk'un kurgusu Selçuklu kültürel sentezi hakkında ne tür bir tarihsel soru doğurmaktadır?</b>",
        secenekler: [
            "A) Selçuklu sanatı özgün bir yaratım mı yoksa tamamen başka kültürlerden alıntı mı?",
            "B) Selçuklu kültürünün İran, Arap ve Bizans etkilerini absorbe ederken seçim mi yoksa sentez mi yaptığı; doğunun ve batının sanat anlayışlarını nasıl bütünleştirdiği ya da ayrıştırdığı",
            "C) Osmanlı sanatının Selçuklu döneminden hiçbir iz taşıyıp taşımadığı",
            "D) Pamuk'un romanının Selçuklu tarihini ne ölçüde doğru yansıttığı",
            "E) Selçuklu minyatür sanatının Osmanlı döneminde neden terk edildiği"
        ],
        cevap: "B) Selçuklu kültürünün İran, Arap ve Bizans etkilerini absorbe ederken seçim mi yoksa sentez mi yaptığı; doğunun ve batının sanat anlayışlarını nasıl bütünleştirdiği ya da ayrıştırdığı",
        aciklama: "Pamuk'un kurgusu, kökleri Selçuklu döneminе uzanan bir soruyu şiirsel biçimde formüle etmektedir: Farklı kültürel etkileri karşılaştığında bu etkilerden birini seçmek mi, yoksa bunları yeni bir sentezde eritmek mi? Selçuklu'nun İran, Arap ve Bizans etkilerini absorbe ediş biçimi, bu soruyu kendi döneminde de somutlaştırmaktadır."
    },
    {
        soru: "[Görsel: Selçuklu Sultanları ve İslam Dünyası] <i>\"Türk devletlerinin bu dönemde yalnızca bir bölgeyi fetheden siyasi birimler olmadığını kavramak gerekir. Selçuklular, İslam'ın siyasi-meşruiyet çerçevesini dönüştürdü: Türk sultanları artık yalnızca ordu komutanları değil, halifeliği koruyan gazi liderler olarak konumlandı. Bu dönüşüm, İslam siyasi düşüncesine kalıcı bir miras bıraktı.\" — Marshall Hodgson, İslam'ın Serüveni: Bir Dünya Medeniyetinde Vicdan ve Tarih, çev. Alp Eker, İz Yayıncılık, 1995, s. 407</i><br><br><b>Hodgson'ın yorumuna göre Selçukluların İslam dünyasına en kalıcı siyasi mirası nedir ve bu miras niçin salt bir askeri fetih anlatısının ötesinde anlam taşımaktadır?</b>",
        secenekler: [
            "A) En kalıcı miras coğrafi genişleme; önemi yeni toprakların İslam'a kazandırılmasındadır",
            "B) En kalıcı miras İslam'ın siyasi-meşruiyet çerçevesinin dönüştürülmesidir: Sultanların yalnızca ordu komutanı değil halifeliği koruyan gazi liderler olarak konumlandırılması, İslam siyasi düşüncesini kalıcı biçimde etkiledi",
            "C) En kalıcı miras Farsça'nın devlet dili olarak benimsenmesidir",
            "D) En kalıcı miras kervansaray ağının oluşturulmasıdır; ticaret rotaları yüzyıllarca Selçuklu izini taşıdı",
            "E) En kalıcı miras Bizans'ın nihai çöküşünü hazırlamasıdır"
        ],
        cevap: "B) En kalıcı miras İslam'ın siyasi-meşruiyet çerçevesinin dönüştürülmesidir: Sultanların yalnızca ordu komutanı değil halifeliği koruyan gazi liderler olarak konumlandırılması, İslam siyasi düşüncesini kalıcı biçimde etkiledi",
        aciklama: "Hodgson'ın analizi, Selçuklu mirasını coğrafi fetih ya da kurumsal altyapıyla değil; İslam siyasi düşüncesine yapılan kavramsal katkıyla ölçmektedir. Türk sultanlarının 'halifeliği koruyan gazi lider' olarak yeniden konumlandırılması, meşruiyet teolojisini dönüştürmüş ve bu dönüşüm Osmanlı siyasetine dek uzanan kalıcı bir iz bırakmıştır."
    },
    {
        soru: "[Görsel: Tarih Yazımında Malazgirt Savaşı] <i>\"Malazgirt'in yorumu, Türk tarih yazımında farklı dönemlerde farklı biçimler almıştır. Erken Cumhuriyet tarihçileri savaşı ulusal bilincin doğuşu olarak kutlarken, revizyonist tarihçiler bunu etnik bir olgu değil çok boyutlu bir siyasi süreç olarak yeniden çerçeveledi. Bu yorum farkı, tarihsel olguların değil; tarihçilerin içinde bulunduğu siyasi bağlamın ürünüdür.\" — Halil Berktay, 'Tarih Yazımında Milliyetçilik ve Eleştiri', Toplum ve Bilim, sayı 54, 1991, s. 43</i><br><br><b>Berktay'ın bu pasajı, tarihsel olayların yorumlanması meselesinde ne tür bir epistemolojik uyarı içermektedir?</b>",
        secenekler: [
            "A) Tarihsel olayların doğru yorumu yalnızca birincil kaynaklara başvurularak elde edilebilir",
            "B) Tarih yazımı siyasi bağlamdan bağımsız değildir; aynı olayın farklı dönemlerde farklı çerçevelenmesi, tarihçilerin kendi ideolojik konumlarını olaylara yansıttığını göstermektedir",
            "C) Malazgirt'in etnik bir olgu olduğu artık genel kabul gören bir tarihsel gerçektir",
            "D) Revizyonist tarihçiler Malazgirt'in önemini küçümseyerek nesnel bir yorum sunmuştur",
            "E) Tarih yazımındaki farklılıklar yalnızca kullanılan kaynak çeşitliliğinden kaynaklanmaktadır"
        ],
        cevap: "B) Tarih yazımı siyasi bağlamdan bağımsız değildir; aynı olayın farklı dönemlerde farklı çerçevelenmesi, tarihçilerin kendi ideolojik konumlarını olaylara yansıttığını göstermektedir",
        aciklama: "Berktay'ın pasajı, tarihin tarafsız bir gerçeklik aktarımı değil; tarihçilerin içinde bulunduğu siyasi bağlamın biçimlendirdiği bir yorum pratiği olduğunu göstermektedir. Erken Cumhuriyet tarihçilerinin ulusal doğuş söylemi ile revizyonist çerçeveleme arasındaki fark; aynı olguların farklı ideolojik merceklerden nasıl farklı anlamlar taşıyabileceğini somutlaştırmaktadır."
    },
    {
        soru: "[Görsel: Moğol İstilası ve Osmanlı'nın Yükselişi] <i>\"Moğol istilası Anadolu üzerinde yıkıcı bir etki bırakmış olsa da bu istila paradoks biçimde Osmanlı'nın yükselişine de zemin hazırladı. Moğol tahribatı, hem Batı sınırlarına yığılan Türkmen nüfusunu artırdı hem de merkezî Selçuklu otoritesini çökerterek bu nüfusun örgütlendiği yeni siyasi yapılara (beylikler) kapı araladı. Yıkımdan doğan bu dolaylı kurgu, tarihsel nedensellik anlayışını zorlamaktadır.\" — Cemal Kafadar, İki Cihan Arasında: Osmanlı Devletinin Kuruluşu, çev. Ceren Gürkan, Birleşik Yayınevi, 2010, s. 84</i><br><br><b>Kafadar'ın bu analizine göre Moğol istilasının Osmanlı'nın yükselişiyle ilişkisi tarihsel nedensellik bağlamında nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Moğol istilası ve Osmanlı'nın yükselişi arasında doğrudan ve bilinçli bir nedensellik zinciri vardır",
            "B) Moğol istilasının Osmanlı'yı doğrudan yaratmadığı; ancak tahribat yoluyla yeni demografik baskıları ve siyasi boşlukları ortaya çıkardığı ve bu yapısal koşulların Osmanlı'nın filizlendiği zemini hazırladığı —dolaylı nedensellik— görülmektedir",
            "C) Moğol istilası Osmanlı'nın yükselişini engelledi; Osmanlı'nın başarısı Moğol baskısına rağmen gerçekleşti",
            "D) İki olay arasında herhangi bir anlamlı tarihsel bağ bulunmamaktadır; Osmanlı iç Anadolu dinamiklerinin tamamen bağımsız bir ürünüdür",
            "E) Moğollar Osmanlı hanedanını bizzat destekleyerek güçlenmesini sağladı"
        ],
        cevap: "B) Moğol istilasının Osmanlı'yı doğrudan yaratmadığı; ancak tahribat yoluyla yeni demografik baskıları ve siyasi boşlukları ortaya çıkardığı ve bu yapısal koşulların Osmanlı'nın filizlendiği zemini hazırladığı —dolaylı nedensellik— görülmektedir",
        aciklama: "Kafadar, yıkımdan yükselişe giden yolu doğrudan değil dolaylı nedensellik çerçevesinde okumaktadır: Moğollar Osmanlı'yı bilinçli olarak yaratmadı; ancak Selçuklu otoritesini çökerterek sınır bölgelerine Türkmen nüfusunu yığdı ve beyliklerin filizleneceği siyasi boşluğu açtı."
    },
    {
        soru: "[Görsel: Selçuklularda Töre ve İslam Hukuku] <i>\"Türk toplulukların İslamiyet'i kabulü ile siyasi güç kazanma süreci arasındaki ilişki düz değil, karmaşık bir etkileşimi yansıtır. Selçuklu sultanları İslam hukukunu benimserken Orta Asya töre geleneğini de uygulamayı sürdürdü. Bu çift yasal çerçeve, sultanın hem İslam dünyasının koruyucusu hem de kendi boyunun 'han'ı olarak meşruiyet inşa etmesini mümkün kıldı.\" — İbrahim Kafesoğlu, Selçuklu Ailesi'nin Menşei Hakkında, Tarih Dergisi, 1955, cilt VI, s. 16</i><br><br><b>Kafesoğlu'nun analizi Selçuklu meşruiyet anlayışını nasıl çerçevelemektedir ve bu çerçeveleme günümüz tarih yazımı açısından neden önem taşımaktadır?</b>",
        secenekler: [
            "A) Selçuklu meşruiyeti tamamen İslam kaynaklıydı; töre geleneği iktidarı pekiştirmede hiçbir işlev görmedi",
            "B) Selçuklu meşruiyeti İslam hukuku ile Orta Asya töre geleneğini iç içe geçiren çift katmanlı bir yapıya sahipti; bu okuma, Türk-İslam sentezinin basit bir geçiş sürecinden ziyade karmaşık bir melezleşme pratiği olduğunu ortaya koymaktadır",
            "C) Selçuklu sultanları İslam'ı siyasi araç olarak kullandı; gerçek inançları Orta Asya geleneklerine bağlıydı",
            "D) Çift yasal çerçeve Selçuklu yönetiminde ciddi meşruiyet çelişkilerine yol açtı ve devleti istikrarsızlaştırdı",
            "E) Töre geleneği İslam hukukuyla çatıştığı her durumda terk edildi"
        ],
        cevap: "B) Selçuklu meşruiyeti İslam hukuku ile Orta Asya töre geleneğini iç içe geçiren çift katmanlı bir yapıya sahipti; bu okuma, Türk-İslam sentezinin basit bir geçiş sürecinden ziyade karmaşık bir melezleşme pratiği olduğunu ortaya koymaktadır",
        aciklama: "Kafesoğlu, Selçuklu meşruiyet anlayışının İslam hukuku ile Orta Asya töre geleneğini aynı anda taşıyan çift katmanlı bir yapıya sahip olduğunu ortaya koymaktadır. Bu okuma, Türk-İslam sentezini doğrusal bir dönüşüm değil; iki ayrı meşruiyet çerçevesinin karmaşık biçimde iç içe geçtiği bir melezleşme pratiği olarak çerçevelemektedir."
    },
    {
        soru: "[Görsel: Tarihte Uzun Soluklu Süreçler] <i>\"1040'tan 1299'a uzanan bu iki buçuk yüzyıl, farklı analiz birimlerinden okunmayı gerektirmektedir. Savaşlar birer olay; hanedanlar birer yapı; göçler ise uzun soluklu süreçlerdir. Türk tarihinin bu dönemini kavramak için salt siyasi olaylar kronolojisi yeterli değildir; demografik dönüşüm, kültürel adaptasyon ve ekonomik yeniden yapılanma süreçleri eş zamanlı okunmalıdır.\" — Fernand Braudel, Akdeniz ve Akdeniz Dünyası (Giriş: Uzun Süre Anlayışı), çev. M. Ali Kılıçbay, İmge Yayınları, 1994, s. 47</i><br><br><b>Braudel'in tarihsel zaman anlayışını Türk tarihinin 1040-1299 dönemine uygulayan bu pasaj, o dönemi anlamak için ne tür bir metodolojik öneri sunmaktadır?</b>",
        secenekler: [
            "A) Bu dönemi anlamak için yalnızca siyasi kronolojiyi takip etmek yeterlidir; sosyal ve ekonomik süreçler ikincil önemdedir",
            "B) Bu dönem, farklı tempolarla işleyen üç analiz biriminin —olaylar (savaşlar), yapılar (hanedanlar) ve uzun soluklu süreçler (göçler, kültürel adaptasyon, ekonomik dönüşüm)— eş zamanlı okunmasını gerektiren çok katmanlı bir tarihsel zemini temsil etmektedir",
            "C) Demografik ve ekonomik süreçler siyasi olaylardan tamamen bağımsız biçimde incelenmelidir",
            "D) Uzun soluklu süreçler siyasi olayları belirleyen tek etkendir; hanedanlar ve savaşlar yalnızca bu süreçlerin yüzeysel yansımalarıdır",
            "E) Braudel'in uzun süre anlayışı yalnızca Akdeniz tarihine uygulanabilir; Türk tarihine aktarılamaz"
        ],
        cevap: "B) Bu dönem, farklı tempolarla işleyen üç analiz biriminin —olaylar (savaşlar), yapılar (hanedanlar) ve uzun soluklu süreçler (göçler, kültürel adaptasyon, ekonomik dönüşüm)— eş zamanlı okunmasını gerektiren çok katmanlı bir tarihsel zemini temsil etmektedir",
        aciklama: "Braudel'in 'uzun süre' anlayışından ilham alan bu pasaj, tarihsel zaman dilimlerinin farklı hızlarda işleyen üç katmana ayrılabileceğini öne sürmektedir: Kısa vadeli olaylar, orta vadeli yapılar ve uzun vadeli süreçler. 1040-1299 dönemini bu üç birimi eş zamanlı okuyarak kavramak, salt kronolojiyi aşan ve derinlikli bir tarihsel anlayışa kapı aralayan metodolojik bir öneride bulunulmaktadır."
    }
];
